@Composable
fun RequirementItem(text: String, checked: Boolean) {
    Row(
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(8.dp),
        modifier = Modifier.fillMaxWidth()
    ) {
        Icon(
            imageVector = if (checked) Icons.Default.CheckCircle else Icons.Default.Cancel,
            contentDescription = null,
            tint = if (checked) Color(0xFF4CAF50) else Color(0xFFE57373),
            modifier = Modifier.size(18.dp)
        )
        Text(
            text = text,
            color = if (checked) Color.Black else Color.Gray,
            fontSize = 13.sp,
            fontWeight = if (checked) FontWeight.Medium else FontWeight.Normal
        )
    }
}

@Composable
fun StoryCardAvatarTop(avatarId: String, fallbackName: String? = null) {
    val char = if (!fallbackName.isNullOrBlank()) {
        fallbackName.trim().firstOrNull()?.uppercaseChar() ?: 'A'
    } else {
        if (avatarId.isNotEmpty() && !avatarId.startsWith("content://") && !avatarId.startsWith("http://") && !avatarId.startsWith("https://") && !avatarId.startsWith("file://") && !avatarId.contains("/")) {
            avatarId.last().uppercaseChar()
        } else {
            'A'
        }
    }
    val fallbackBg = remember(avatarId) {
        val hash = avatarId.hashCode()
        when (hash % 4) {
            0 -> Brush.linearGradient(colors = listOf(Color(0xFF7C4DFF), Color(0xFF9575CD)))
            1 -> Brush.linearGradient(colors = listOf(Color(0xFFFF4081), Color(0xFFFF80AB)))
            2 -> Brush.linearGradient(colors = listOf(Color(0xFF00E5FF), Color(0xFF00B0FF)))
            else -> Brush.linearGradient(colors = listOf(Color(0xFF00E676), Color(0xFF69F0AE)))
        }
    }
    val isUri = avatarId.startsWith("content://") || avatarId.startsWith("http://") || avatarId.startsWith("https://") || avatarId.startsWith("file://") || avatarId.contains("/")
    var loadFailed by remember(avatarId) { mutableStateOf(false) }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .clip(RoundedCornerShape(topStart = 14.dp, topEnd = 14.dp))
    ) {
        if (isUri && !loadFailed) {
            AsyncImage(
                model = avatarId,
                contentDescription = "Create story avatar",
                modifier = Modifier.fillMaxSize(),
                contentScale = ContentScale.Crop,
                onError = { loadFailed = true }
            )
        } else {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(fallbackBg),
                contentAlignment = Alignment.Center
            ) {
                val hasLetter = char != 'A' || (!fallbackName.isNullOrBlank() && fallbackName.trim().firstOrNull()?.uppercaseChar() == 'A')
                if (hasLetter) {
                    Text(
                        text = char.toString(),
                        color = Color.White,
                        fontSize = 32.sp,
                        fontWeight = FontWeight.Bold
                    )
                } else {
                    Icon(
                        imageVector = Icons.Default.Person,
                        contentDescription = "User Avatar Placeholder",
                        tint = Color.White,
                        modifier = Modifier.fillMaxSize(0.6f)
                    )
                }
            }
        }
    }
}

fun extractYouTubeId(urlOrId: String): String {
    if (urlOrId.isBlank()) return ""
    if (!urlOrId.contains("/") && !urlOrId.contains(".")) return urlOrId
    val pattern = "(?i)(?:youtube\\.com/(?:[^/]+/.*|(?:v|e(?:mbed)?)|[^/]+/([^/]+))|youtu\\.be/)([^\"&?/\\s]{11})"
    val compiledPattern = java.util.regex.Pattern.compile(pattern)
    val matcher = compiledPattern.matcher(urlOrId)
    if (matcher.find()) {
        val g1 = matcher.group(1)
        val g2 = matcher.group(2)
        return g2 ?: g1 ?: urlOrId
    }
    val queryIdx = urlOrId.indexOf("v=")
    if (queryIdx != -1 && queryIdx + 2 < urlOrId.length) {
        val ampIdx = urlOrId.indexOf("&", queryIdx)
        return if (ampIdx != -1) urlOrId.substring(queryIdx + 2, ampIdx) else urlOrId.substring(queryIdx + 2)
    }
    return urlOrId
}

fun extractTwitchChannel(urlOrChannel: String): String {
    if (urlOrChannel.isBlank()) return ""
    if (urlOrChannel.contains("twitch.tv/")) {
        val parts = urlOrChannel.split("twitch.tv/")
        if (parts.size > 1) {
            val part = parts[1]
            val slashIdx = part.indexOf("/")
            return if (slashIdx != -1) part.substring(0, slashIdx) else part
        }
    }
    return urlOrChannel.trim()
}

@androidx.annotation.OptIn(androidx.camera.core.ExperimentalGetImage::class)
@Composable
fun CameraPreview(modifier: Modifier = Modifier) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val lifecycleOwner = androidx.lifecycle.compose.LocalLifecycleOwner.current
    val previewView = remember { androidx.camera.view.PreviewView(context) }

    LaunchedEffect(Unit) {
        val cameraProviderFuture = androidx.camera.lifecycle.ProcessCameraProvider.getInstance(context)
        try {
            val cameraProvider = cameraProviderFuture.get()
            val preview = androidx.camera.core.Preview.Builder().build().also {
                it.setSurfaceProvider(previewView.surfaceProvider)
            }
            val cameraSelector = androidx.camera.core.CameraSelector.DEFAULT_FRONT_CAMERA

            cameraProvider.unbindAll()
            cameraProvider.bindToLifecycle(
                lifecycleOwner,
                cameraSelector,
                preview
            )
        } catch (e: Exception) {
            android.util.Log.e("CameraPreview", "Camera initialization failed: ${e.message}")
        }
    }

    androidx.compose.ui.viewinterop.AndroidView(
        factory = { previewView },
        modifier = modifier
    )
}


