                        val allUsersList by viewModel.allUsers.collectAsStateWithLifecycle()
                        val currentUserState by viewModel.currentUser.collectAsStateWithLifecycle()
                        val suggestedUsers = remember(allUsersList, currentUserState, relationshipPrefs) {
                            val activeUser = currentUserState
                            if (activeUser == null) {
                                emptyList()
                            } else {
                                allUsersList.filter { usr ->
                                    usr.email.lowercase().trim() != activeUser.email.lowercase().trim() && 
                                    usr.displayName.isNotBlank() &&
                                    if (activeUser.isProfileLocked) {
                                        relationshipPrefs.getBoolean("friend_${usr.userId}", false)
                                    } else {
