                        if (isSettingsExpanded) {
                            Column(modifier = Modifier.padding(start = 36.dp, bottom = 12.dp)) {
                                Text("• Privacy Shortcuts", fontSize = 13.sp, color = Color.DarkGray, modifier = Modifier.padding(vertical = 4.dp).clickable {
                                    android.widget.Toast.makeText(context, "Privacy settings are configured automatically! / Privacy is fully secured!", android.widget.Toast.LENGTH_SHORT).show()
                                    showMenuOverlay = false
                                })
                                Text("• Activity Log", fontSize = 13.sp, color = Color.DarkGray, modifier = Modifier.padding(vertical = 4.dp))
                                Text("• Language Settings", fontSize = 13.sp, color = Color.DarkGray, modifier = Modifier.padding(vertical = 4.dp))
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(24.dp))

                    // 6. Log out Button
                    Button(
                        onClick = {
                            viewModel.logout()
                        },
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(48.dp)
                            .testTag("menu_logout_button"),
                        shape = RoundedCornerShape(10.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFE4E6EB))
                    ) {
                        Text(
                            text = "Log out",
                            color = Color.Black,
                            fontSize = 15.sp,
                            fontWeight = FontWeight.ExtraBold
                        )
                    }

                    Spacer(modifier = Modifier.height(24.dp))
                }
            }
        }

        if (currentlyPlayingTrack != null) {
            AuraFloatingMusicPlayer(
                currentlyPlayingTrack = currentlyPlayingTrack!!,
                viewModel = viewModel,
                modifier = Modifier
                    .align(Alignment.BottomCenter)
                    .padding(bottom = if (isBottomBarVisible) 80.dp else 16.dp)
            )
        }

        // --- 4. Premium Lavender Video Player Simulation Panel (IMMERSIVE EXPERIENCE) ---
        state.activeReplayPost?.let { post ->
            val totalSeconds = remember(post.content) {
                val tag = "[DURATION:"
                if (post.content.contains(tag)) {
                    val parsed = post.content.substringAfter(tag).substringBefore("]", "")
                    val parts = parsed.split(":")
                    if (parts.size >= 2) {
                        val mins = parts[0].toIntOrNull() ?: 0
                        val secs = parts[1].toIntOrNull() ?: 0
                        ((mins * 60) + secs).coerceAtLeast(1)
                    } else {
                        504
                    }
                } else {
                    504
                }
            }
            val elapsedSeconds = (state.videoProgress * totalSeconds).toInt()
            
            val minutesStr = "%02d".format(elapsedSeconds / 60)
            val secondsStr = "%02d".format(elapsedSeconds % 60)
            val durationMinutesStr = "%02d".format(totalSeconds / 60)
            val durationSecondsStr = "%02d".format(totalSeconds % 60)
            
            if (state.isVideoFullscreen) {
                BackHandler {
                    viewModel.setVideoMinimized(true)
                }
                
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(Color(0xFF09061A))
                        .statusBarsPadding()
                        .navigationBarsPadding(),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(16.dp)
                    ) {
                        // A: Player Header
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(vertical = 4.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Box(
                                    modifier = Modifier
                                        .size(32.dp)
                                        .clip(CircleShape)
                                        .background(Color(0xFF7C4DFF))
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Tv,
                                        contentDescription = "Aura Replay Channel",
                                        tint = Color.White,
                                        modifier = Modifier.size(16.dp).align(Alignment.Center)
                                    )
                                }
                                Spacer(modifier = Modifier.width(10.dp))
                                Column {
                                    Text(
                                        text = "AURA TV RECAST 🎙️",
                                        color = Color.White,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.ExtraBold
                                    )
                                    Text(
                                        text = "Replay of broadcast by ${post.authorName}",
                                        color = Color.LightGray,
                                        fontSize = 10.sp
                                    )
                                }
                            }
                            
                            Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                IconButton(
                                    onClick = { viewModel.setVideoMinimized(true) },
                                    modifier = Modifier.size(36.dp)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.ExpandMore,
                                        contentDescription = "Minimize video replay player",
                                        tint = Color.White
                                    )
                                }
                                IconButton(
                                    onClick = { viewModel.closePlayer() },
                                    modifier = Modifier.size(36.dp)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Close,
                                        contentDescription = "Close video replay player",
                                        tint = Color(0xFFFF5252)
                                    )
                                }
                            }
                        }
                        
                        // B: Video Display Area (Live stream camera video feed or pulsing avatar)
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(220.dp)
                                .clip(RoundedCornerShape(16.dp))
                                .background(Color(0xFF0F0B24)),
                            contentAlignment = Alignment.Center
                        ) {
                            // Animated sweeping auroral background
                            val infiniteTransition = androidx.compose.animation.core.rememberInfiniteTransition()
                            val colorShiftAngle by infiniteTransition.animateFloat(
                                initialValue = 0f,
                                targetValue = 360f,
                                animationSpec = androidx.compose.animation.core.infiniteRepeatable(
                                    animation = androidx.compose.animation.core.tween(12000, easing = androidx.compose.animation.core.LinearEasing),
                                    repeatMode = androidx.compose.animation.core.RepeatMode.Restart
                                )
                            )
                            val pulseScale by infiniteTransition.animateFloat(
                                initialValue = 0.95f,
                                targetValue = 1.08f,
                                animationSpec = androidx.compose.animation.core.infiniteRepeatable(
                                    animation = androidx.compose.animation.core.tween(2000, easing = androidx.compose.animation.core.FastOutSlowInEasing),
                                    repeatMode = androidx.compose.animation.core.RepeatMode.Reverse
                                )
                            )

                            // Show the actual camera live stream video preview!
                            if (state.isVideoPlaying) {
                                CameraPreview(modifier = Modifier.fillMaxSize())
                            } else {
                                // Sweeping atmosphere when paused
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.sweepGradient(
                                                colors = listOf(
                                                    Color(0xFF7C4DFF).copy(alpha = 0.25f),
                                                    Color(0xFFEC4899).copy(alpha = 0.15f),
                                                    Color(0xFF3B82F6).copy(alpha = 0.2f),
                                                    Color(0xFF7C4DFF).copy(alpha = 0.25f)
                                                )
                                            )
                                        )
                                )
                                // Render a camera background with low alpha to look like a paused stream video
                                CameraPreview(modifier = Modifier.fillMaxSize().graphicsLayer(alpha = 0.25f))
                            }

                            // Grid scanline overlay filter
                            androidx.compose.foundation.Canvas(modifier = Modifier.fillMaxSize()) {
                                val gridGap = 16.dp.toPx()
                                val lineWeight = 0.6.dp.toPx()
                                val lineColor = Color.White.copy(alpha = 0.05f)
                                // Vertical lines
                                var x = 0f
                                while (x < size.width) {
                                    drawLine(lineColor, androidx.compose.ui.geometry.Offset(x, 0f), androidx.compose.ui.geometry.Offset(x, size.height), lineWeight)
                                    x += gridGap
                                }
                                // Horizontal lines
                                var y = 0f
                                while (y < size.height) {
                                    drawLine(lineColor, androidx.compose.ui.geometry.Offset(0f, y), androidx.compose.ui.geometry.Offset(size.width, y), lineWeight)
                                    y += gridGap
                                }
                                
                                // Reticle corner framing brackets
                                val bracketLen = 20.dp.toPx()
                                val bracketThick = 2.dp.toPx()
                                val bracketColor = Color.White.copy(alpha = 0.35f)
                                
                                // Top Left
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(15.dp.toPx(), 15.dp.toPx()), androidx.compose.ui.geometry.Offset(15.dp.toPx() + bracketLen, 15.dp.toPx()), bracketThick)
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(15.dp.toPx(), 15.dp.toPx()), androidx.compose.ui.geometry.Offset(15.dp.toPx(), 15.dp.toPx() + bracketLen), bracketThick)
                                
                                // Top Right
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), 15.dp.toPx()), androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx() - bracketLen, 15.dp.toPx()), bracketThick)
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), 15.dp.toPx()), androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), 15.dp.toPx() + bracketLen), bracketThick)
                                
                                // Bottom Left
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(15.dp.toPx(), size.height - 15.dp.toPx()), androidx.compose.ui.geometry.Offset(15.dp.toPx() + bracketLen, size.height - 15.dp.toPx()), bracketThick)
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(15.dp.toPx(), size.height - 15.dp.toPx()), androidx.compose.ui.geometry.Offset(15.dp.toPx(), size.height - 15.dp.toPx() - bracketLen), bracketThick)
                                
                                // Bottom Right
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), size.height - 15.dp.toPx()), androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx() - bracketLen, size.height - 15.dp.toPx()), bracketThick)
                                drawLine(bracketColor, androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), size.height - 15.dp.toPx()), androidx.compose.ui.geometry.Offset(size.width - 15.dp.toPx(), size.height - 15.dp.toPx() - bracketLen), bracketThick)
                            }

                            // If paused, show the Avatar with a pulsing Play overlay to invite the user to play!
                            if (!state.isVideoPlaying) {
                                Box(
                                    modifier = Modifier
                                        .size(90.dp)
                                        .then(Modifier.graphicsLayer(scaleX = pulseScale, scaleY = pulseScale))
                                        .background(Color(0xFF9333EA).copy(alpha = 0.2f), CircleShape)
                                        .border(2.dp, Color(0xFFC084FC), CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    if (post.authorAvatar.isNotEmpty()) {
                                        androidx.compose.foundation.Image(
                                            painter = coil.compose.rememberAsyncImagePainter(post.authorAvatar),
                                            contentDescription = "Avatar",
                                            modifier = Modifier
                                                .fillMaxSize()
                                                .clip(CircleShape),
                                            contentScale = androidx.compose.ui.layout.ContentScale.Crop
                                        )
                                    } else {
                                        Text(
                                            text = post.authorName.take(1).uppercase(),
                                            color = Color.White,
                                            fontSize = 32.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }

                            // Waveform bars overlay at the bottom
                            Row(
                                modifier = Modifier
                                    .align(Alignment.BottomStart)
                                    .padding(start = 24.dp, bottom = 16.dp),
                                horizontalArrangement = Arrangement.spacedBy(4.dp),
                                verticalAlignment = Alignment.Bottom
                            ) {
                                repeat(8) { i ->
                                    var hVal by remember { mutableStateOf(10f) }
                                    if (state.isVideoPlaying) {
                                        LaunchedEffect(state.isVideoPlaying) {
                                            while (true) {
                                                hVal = (8..45).random().toFloat()
                                                kotlinx.coroutines.delay((80 + i * 12).toLong())
                                            }
                                        }
                                    }
                                    Box(
                                        modifier = Modifier
                                            .width(4.dp)
                                            .height(hVal.dp)
                                            .background(
                                                Brush.verticalGradient(
                                                    colors = listOf(Color(0xFF22D3EE), Color(0xFF818CF8))
                                                ),
                                                RoundedCornerShape(1.dp)
                                            )
                                    )
                                }
                            }

                            // RED blinking live indicator card
                            Box(
                                modifier = Modifier
                                    .align(Alignment.TopStart)
                                    .padding(20.dp)
                                    .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 8.dp, vertical = 4.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    var isDotVisible by remember { mutableStateOf(true) }
                                    if (state.isVideoPlaying) {
                                        LaunchedEffect(state.isVideoPlaying) {
                                            while (true) {
                                                isDotVisible = !isDotVisible
                                                kotlinx.coroutines.delay(600)
                                            }
                                        }
                                    }
                                    Box(
                                        modifier = Modifier
                                            .size(8.dp)
                                            .background(
                                                if (isDotVisible && state.isVideoPlaying) Color.Red else Color.Gray,
                                                CircleShape
                                            )
                                    )
                                    Text(
                                        text = "LIVE REPLAY ● HD",
                                        color = Color.White,
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }

                            // Interactive camera preview filter look
                            Box(
                                modifier = Modifier
                                    .align(Alignment.BottomEnd)
                                    .padding(16.dp)
                                    .border(1.dp, Color.White.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                                    .background(Color.Black.copy(alpha = 0.75f))
                                    .padding(horizontal = 6.dp, vertical = 3.dp)
                            ) {
                                Text(
                                    text = "1080P UltraHD 📹",
                                    color = Color.White,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                        
                        // C: Video Replay Details & Title
                        Spacer(modifier = Modifier.height(14.dp))
                        Text(
                            text = post.content,
                            color = Color.White,
                            fontSize = 15.sp,
                            fontWeight = FontWeight.Bold,
                            maxLines = 2,
                            overflow = TextOverflow.Ellipsis
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = "Broadcast ended: ${formatRelativeTime(post.timestamp)} • Simulating interactive playback",
                            color = Color.Gray,
                            fontSize = 10.5.sp
                        )
                        
                        Divider(
                            color = Color.White.copy(alpha = 0.1f),
                            modifier = Modifier.padding(vertical = 12.dp)
                        )
                        
                        // D: Live Replay Comments Panel (Real interactive comments database driven)
                        val replayComments by viewModel.getCommentsFlow(post.postId).collectAsStateWithLifecycle(initialValue = emptyList())
                        var pendingCommentText by remember { mutableStateOf("") }
                        
                        Text(
                            text = "REAL-TIME COMMENTS 💬",
                            color = Color(0xFFA78BFA),
                            fontSize = 11.sp,
                            fontWeight = FontWeight.ExtraBold
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        
                        // LazyColumn of chat
                        Box(
                            modifier = Modifier
                                .weight(1f)
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(12.dp))
                                .background(Color.White.copy(alpha = 0.04f))
                                .padding(10.dp)
                        ) {
                            val listState = androidx.compose.foundation.lazy.rememberLazyListState()
                            LaunchedEffect(replayComments.size) {
                                if (replayComments.isNotEmpty()) {
                                    listState.animateScrollToItem(replayComments.size - 1)
                                }
                            }
                            
                            LazyColumn(
                                state = listState,
                                modifier = Modifier.fillMaxSize(),
                                verticalArrangement = Arrangement.spacedBy(6.dp)
                            ) {
                                items(replayComments.size) { index ->
                                    val item = replayComments[index]
                                    Row(verticalAlignment = Alignment.Top) {
                                        Text(
                                            text = "${item.authorName}: ",
                                            color = Color(0xFFDDD6FE),
                                            fontSize = 11.5.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        Text(
                                            text = item.text,
                                            color = Color.White,
                                            fontSize = 11.5.sp
                                        )
                                    }
                                }
                            }
                        }
                        
                        // Comment input
                        Spacer(modifier = Modifier.height(8.dp))
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                        ) {
                            OutlinedTextField(
                                value = pendingCommentText,
                                onValueChange = { pendingCommentText = it },
                                modifier = Modifier
                                    .weight(1f)
                                    .height(48.dp),
                                placeholder = { Text("Add comment... 💬", color = Color.Gray, fontSize = 11.sp) },
                                singleLine = true,
                                shape = RoundedCornerShape(24.dp),
                                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = Color(0xFF7C4DFF),
                                    unfocusedBorderColor = Color(0xFF33206E),
                                    focusedContainerColor = Color(0xFF140E2D),
                                    unfocusedContainerColor = Color(0xFF140E2D)
                                )
                            )
                            IconButton(
                                onClick = {
                                    if (pendingCommentText.isNotBlank()) {
                                        viewModel.submitCommentsForReplay(post.postId, pendingCommentText)
                                        pendingCommentText = ""
                                    }
                                },
                                modifier = Modifier
                                    .size(44.dp)
                                    .background(Color(0xFF7C4DFF), CircleShape)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Send,
                                    contentDescription = "Send Replay message",
                                    tint = Color.White,
                                    modifier = Modifier.size(16.dp)
                                )
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(14.dp))
                        
                        // E: Bold Lavender Audio/Video Player controls
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(16.dp))
                                .background(Color(0xFF140F2E))
                                .border(1.0.dp, Color(0xFF32226A), RoundedCornerShape(16.dp))
                                .padding(12.dp)
                        ) {
                            // Slider with current/elapsed speed
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Text(
                                    text = "$minutesStr:$secondsStr",
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontFamily = FontFamily.Monospace,
                                    fontWeight = FontWeight.Bold
                                )
                                
                                Slider(
                                    value = state.videoProgress,
                                    onValueChange = { viewModel.setVideoProgress(it) },
                                    modifier = Modifier
                                        .weight(1f)
                                        .padding(horizontal = 8.dp),
                                    colors = SliderDefaults.colors(
                                        thumbColor = Color(0xFFA78BFA),
                                        activeTrackColor = Color(0xFF7C4DFF),
                                        inactiveTrackColor = Color(0xFF261D4C)
                                    )
                                )
                                
                                Text(
                                    text = "$durationMinutesStr:$durationSecondsStr",
                                    color = Color.Gray,
                                    fontSize = 11.sp,
                                    fontFamily = FontFamily.Monospace,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                            
                            Spacer(modifier = Modifier.height(6.dp))
                            
                            // Audio/Video control buttons
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceEvenly
                            ) {
                                // 1. Playback Speed Selector Chip
                                Row(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(12.dp))
                                        .background(Color(0xFF251A4D))
                                        .clickable { viewModel.changePlaybackSpeed() }
                                        .padding(horizontal = 10.dp, vertical = 5.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Speed,
                                        contentDescription = "Playback Speed",
                                        tint = Color(0xFFDDD6FE),
                                        modifier = Modifier.size(12.dp)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text(
                                        text = "${state.videoPlaybackSpeed}x",
                                        color = Color.White,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.ExtraBold
                                    )
                                }
                                
                                // 2. Rewind -10s
                                Box(
                                    modifier = Modifier
                                        .size(38.dp)
                                        .background(Color(0xFF251A4D), CircleShape)
                                        .clickable { viewModel.skipBackward() },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.FastRewind,
                                        contentDescription = "Skip back 10 seconds",
                                        tint = Color.White,
                                        modifier = Modifier.size(18.dp)
                                    )
                                }
                                
                                // 3. Central Play / Pause Toggle Circle
                                Box(
                                    modifier = Modifier
                                        .size(54.dp)
                                        .background(
                                            Brush.radialGradient(
                                                colors = listOf(Color(0xFFA78BFA), Color(0xFF7C4DFF))
                                            ),
                                            CircleShape
                                        )
                                        .clickable { viewModel.toggleVideoPlayPause() },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = if (state.isVideoPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                                        contentDescription = "Toggle video replay play or pause state",
                                        tint = Color.White,
                                        modifier = Modifier.size(28.dp)
                                    )
                                }
                                
                                // 4. Forward +10s
                                Box(
                                    modifier = Modifier
                                        .size(38.dp)
                                        .background(Color(0xFF251A4D), CircleShape)
                                        .clickable { viewModel.skipForward() },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.FastForward,
                                        contentDescription = "Skip forward 10 seconds",
                                        tint = Color.White,
                                        modifier = Modifier.size(18.dp)
                                    )
                                }

                                // 5. Picture in Picture Toggle
                                Box(
                                    modifier = Modifier
                                        .size(36.dp)
                                        .background(Color(0xFF251A4D), CircleShape)
                                        .clickable { viewModel.setVideoMinimized(true) },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.ExpandMore,
                                        contentDescription = "Enable Picture-in-picture floating mini mode",
                                        tint = Color(0xFFA78BFA),
                                        modifier = Modifier.size(16.dp)
                                    )
                                }
                            }
                        }
                    }
                }
            } else if (state.isVideoMinimized) {
                // F: Draggable Draggable Minimized picture-in-picture floating block (Floating Bottom Right)
                Box(
                    modifier = Modifier
                        .align(Alignment.BottomEnd)
                        .padding(end = 16.dp, bottom = 82.dp)
                        .width(160.dp)
                        .height(115.dp)
                        .shadow(6.dp, RoundedCornerShape(12.dp))
                        .clip(RoundedCornerShape(12.dp))
                        .background(Color.Black)
                        .border(1.5.dp, Color(0xFF7C4DFF), RoundedCornerShape(12.dp))
                        .clickable { viewModel.setVideoFullscreen(true) }
                ) {
                    // Simulated mini hacker waves inside
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .background(
                                Brush.verticalGradient(
                                    colors = listOf(Color(0xFF251F56), Color(0xFF0C0A1C))
                                )
                            ),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Spacer(modifier = Modifier.height(18.dp))
                            Row(
                                horizontalArrangement = Arrangement.spacedBy(3.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                repeat(5) { i ->
                                    var hVal by remember { mutableStateOf(8f) }
                                    if (state.isVideoPlaying) {
                                        LaunchedEffect(state.isVideoPlaying) {
                                            while (true) {
                                                hVal = (4..30).random().toFloat()
                                                kotlinx.coroutines.delay((70 + i * 15).toLong())
                                            }
                                        }
                                    }
                                    Box(
                                        modifier = Modifier
                                            .width(3.dp)
                                            .height(hVal.dp)
                                            .background(Color(0xFFA78BFA), RoundedCornerShape(1.dp))
                                    )
                                }
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = "Aura Replay Link 🎥",
                                color = Color.White,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.Bold
                            )
                            Text(
                                text = "$minutesStr:$secondsStr / $durationMinutesStr:$durationSecondsStr",
                                color = Color.LightGray,
                                fontSize = 8.sp,
                                fontFamily = FontFamily.Monospace
                            )
                        }
                    }
                    
                    // Small Header Controls in Mini floating video Window
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(6.dp)
                            .align(Alignment.TopCenter),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(
                            modifier = Modifier
                                .size(10.dp)
                                .background(Color.Red, CircleShape)
                        )
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Box(
                                modifier = Modifier
                                    .size(20.dp)
                                    .background(Color.Black.copy(alpha = 0.6f), CircleShape)
                                    .clickable { viewModel.setVideoFullscreen(true) },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Fullscreen,
                                    contentDescription = "Maximize full-screen back",
                                    tint = Color.White,
                                    modifier = Modifier.size(12.dp)
                                )
                            }
                            Box(
                                modifier = Modifier
                                    .size(20.dp)
                                    .background(Color.Black.copy(alpha = 0.6f), CircleShape)
                                    .clickable { viewModel.closePlayer() },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Close,
                                    contentDescription = "Close player",
                                    tint = Color(0xFFFF5252),
                                    modifier = Modifier.size(12.dp)
                                )
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AuraFloatingMusicPlayer(
    currentlyPlayingTrack: String,
    viewModel: AuraViewModel,
    modifier: Modifier = Modifier
) {
    var isExpanded by remember { mutableStateOf(false) }
    var rotationAngle by remember { mutableStateOf(0f) }

    // Disk spinning animation when track is playing
    LaunchedEffect(currentlyPlayingTrack) {
        while (true) {
            kotlinx.coroutines.delay(16)
            rotationAngle = (rotationAngle + 1f) % 360f
        }
    }

    val trackItem = remember(currentlyPlayingTrack) {
        currentlyPlayingTrack.toYouTubeTrackItem()
    }

    val finalUrl = remember(trackItem) {
        val clean = (trackItem.previewUrl ?: "").trim()
        if (clean.startsWith("http://") || clean.startsWith("https://")) {
            if (clean.contains("youtu.be/")) {
                val id = clean.substringAfter("youtu.be/").substringBefore("?").substringBefore("&").trim()
                "https://www.youtube.com/embed/$id?autoplay=1&enablejsapi=1&origin=https://www.youtube.com"
            } else if (clean.contains("v=")) {
                val id = clean.substringAfter("v=").substringBefore("&").substringBefore("?").trim()
                "https://www.youtube.com/embed/$id?autoplay=1&enablejsapi=1&origin=https://www.youtube.com"
            } else if (clean.contains("embed/")) {
                val id = clean.substringAfter("embed/").substringBefore("?").substringBefore("&").trim()
                "https://www.youtube.com/embed/$id?autoplay=1&enablejsapi=1&origin=https://www.youtube.com"
            } else {
                clean
            }
        } else {
            val encodedQuery = java.net.URLEncoder.encode(clean.ifBlank { trackItem.name }, "UTF-8")
            "https://www.youtube.com/embed?listType=search&list=$encodedQuery&autoplay=1&enablejsapi=1&origin=https://www.youtube.com"
        }
    }

    Card(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 8.dp)
            .shadow(12.dp, RoundedCornerShape(16.dp)),
        colors = CardDefaults.cardColors(
            containerColor = Color(0xFF130E26)
        ),
        shape = RoundedCornerShape(16.dp),
        border = BorderStroke(1.5.dp, Color(0xFF7C4DFF).copy(alpha = 0.6f))
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp)
        ) {
            // Header controls
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier.weight(1f)
                ) {
                    Box(
                        modifier = Modifier
                            .size(36.dp)
                            .graphicsLayer(rotationZ = rotationAngle)
                            .clip(CircleShape)
                            .background(Color(0xFF7C4DFF).copy(alpha = 0.2f)),
                        contentAlignment = Alignment.Center
                    ) {
                        if (trackItem.imageUrl != null) {
                            AsyncImage(
                                model = trackItem.imageUrl,
                                contentDescription = "Cover Art",
                                modifier = Modifier.fillMaxSize().clip(CircleShape),
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop
                            )
                        } else {
                            Text("🎵", fontSize = 18.sp)
                        }
                    }
                    
                    Spacer(modifier = Modifier.width(10.dp))
                    
                    Column {
                        Text(
                            text = trackItem.name,
                            fontWeight = FontWeight.Bold,
                            fontSize = 13.sp,
                            color = Color.White,
                            maxLines = 1,
                            overflow = TextOverflow.Ellipsis
                        )
                        Text(
                            text = trackItem.artistName,
                            fontSize = 10.sp,
                            color = Color(0xFFA58AFF),
                            maxLines = 1,
                            overflow = TextOverflow.Ellipsis
                        )
                    }
                }
                
                Row(verticalAlignment = Alignment.CenterVertically) {
                    IconButton(
                        onClick = { isExpanded = !isExpanded },
                        modifier = Modifier.size(32.dp)
                    ) {
                        Icon(
                            imageVector = if (isExpanded) Icons.Default.KeyboardArrowDown else Icons.Default.KeyboardArrowUp,
                            contentDescription = if (isExpanded) "Toggle Player Layout" else "Expand Player Layout",
                            tint = Color.White,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                    
                    Spacer(modifier = Modifier.width(4.dp))
                    
                    IconButton(
                        onClick = { viewModel.stopMusicPlayback() },
                        modifier = Modifier.size(32.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Close,
                            contentDescription = "Stop Playback",
                            tint = Color(0xFFFF5252),
                            modifier = Modifier.size(18.dp)
                        )
                    }
                }
            }
            
            // Native YouTube Music Sync Dashboard container
            if (isExpanded) {
                Spacer(modifier = Modifier.height(10.dp))
                val context = androidx.compose.ui.platform.LocalContext.current
                
                // Formulate HTML wrapper for the YouTube Embed Video Player with proper styling
                val htmlContent = remember(finalUrl) {
                    """
                    <!DOCTYPE html>
                    <html>
                    <head>
                        <meta name="viewport" content="width=device-width, initial-scale=1.0">
                        <style>
                            body, html { margin:0; padding:0; width:100%; height:100%; background:black; overflow:hidden; }
                            iframe { width:100%; height:100%; border:none; }
                        </style>
                    </head>
                    <body>
                        <iframe 
                            src="$finalUrl" 
                            allow="autoplay; encrypted-media" 
                            allowfullscreen>
                        </iframe>
                    </body>
                    </html>
                    """.trimIndent()
                }

                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .wrapContentHeight()
                        .border(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.5f), RoundedCornerShape(12.dp)),
                    colors = CardDefaults.cardColors(
                        containerColor = Color(0xFF1C1438)
                    ),
                    shape = RoundedCornerShape(12.dp)
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(14.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                imageVector = Icons.Default.MusicVideo,
                                contentDescription = "Active Sync",
                                tint = Color(0xFFB388FF),
                                modifier = Modifier.size(24.dp)
                            )
                            Spacer(modifier = Modifier.width(10.dp))
                            Column(modifier = Modifier.weight(1f)) {
                                Text(
                                    text = "Aura Playback Synced! ⚡",
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 13.5.sp,
                                    color = Color.White
                                )
                                Text(
                                    text = "Connected with YouTube Music App",
                                    fontSize = 10.5.sp,
                                    color = Color.LightGray
                                )
                            }
                            
                            // Pulsing frequency bars
                            Row(
                                horizontalArrangement = Arrangement.spacedBy(3.dp),
                                verticalAlignment = Alignment.Bottom,
                                modifier = Modifier.height(16.dp)
                            ) {
                                repeat(5) { i ->
                                    var h by remember { mutableStateOf(8f) }
                                    LaunchedEffect(key1 = currentlyPlayingTrack) {
                                        while (true) {
                                            h = (6..20).random().toFloat()
                                            kotlinx.coroutines.delay((60 + i * 15).toLong())
                                        }
                                    }
                                    Box(
                                        modifier = Modifier
                                            .width(2.5.dp)
                                            .height(h.dp)
                                            .background(Color(0xFFE040FB), RoundedCornerShape(1.dp))
                                    )
                                }
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(12.dp))
                        
                        // Core Video/Audio playback container directly inside Aura app
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(160.dp)
                                .clip(RoundedCornerShape(12.dp))
                                .background(Color.Black)
                                .border(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.3f), RoundedCornerShape(12.dp))
                        ) {
                            androidx.compose.ui.viewinterop.AndroidView(
                                factory = { ctx ->
                                    android.webkit.WebView(ctx).apply {
                                        settings.apply {
                                            javaScriptEnabled = true
                                            mediaPlaybackRequiresUserGesture = false
                                            domStorageEnabled = true
                                            useWideViewPort = true
                                            loadWithOverviewMode = true
                                            // Desktop browser user agent sets full desktop HTML5 player capabilities and bypasses mobile-only restriction 152
                                            userAgentString = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36"
                                        }
                                        webViewClient = object : android.webkit.WebViewClient() {
                                            override fun shouldOverrideUrlLoading(view: android.webkit.WebView?, request: android.webkit.WebResourceRequest?): Boolean {
                                                val reqUrl = request?.url?.toString() ?: return false
                                                if (reqUrl.contains("youtube") || reqUrl.contains("youtu.be")) {
                                                    try {
                                                        var ytMusicUrl = reqUrl.replace("www.youtube.com", "music.youtube.com")
                                                            .replace("m.youtube.com", "music.youtube.com")
                                                        if (ytMusicUrl.contains("youtu.be/")) {
                                                            val id = ytMusicUrl.substringAfter("youtu.be/").substringBefore("?").substringBefore("&")
                                                            ytMusicUrl = "https://music.youtube.com/watch?v=$id"
                                                        }
                                                        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(ytMusicUrl)).apply {
                                                            setPackage("com.google.android.apps.youtube.music")
                                                            addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                                        }
                                                        ctx.startActivity(intent)
                                                        return true
                                                    } catch (e: Exception) {
                                                        try {
                                                            val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(reqUrl)).apply {
                                                                addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                                            }
                                                            ctx.startActivity(intent)
                                                            return true
                                                        } catch (ex: Exception) {}
                                                    }
                                                }
                                                return false
                                            }
                                        }
                                        webChromeClient = android.webkit.WebChromeClient()
                                        layoutParams = android.view.ViewGroup.LayoutParams(
                                            android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                                            android.view.ViewGroup.LayoutParams.MATCH_PARENT
                                        )
                                    }
                                },
                                update = { webView ->
                                    // BaseURL load with youtube.com bypasses standard embedding referrer / domain barriers
                                    webView.loadDataWithBaseURL("https://www.youtube.com", htmlContent, "text/html", "UTF-8", null)
                                },
                                modifier = Modifier.fillMaxSize()
                            )
                        }

                        Spacer(modifier = Modifier.height(12.dp))
                        
                        Text(
                            text = "আপনার YouTube Music-এর সাথে Aura প্লেব্যাক নিখুঁতভাবে সিঙ্ক হয়েছে! ব্যাকগ্রাউন্ডে গানটি সফলভাবে শুনতে ও উপভোগ করতে সরাসরি YT Music ব্যবহার করুন। 🎧💜",
                            fontSize = 11.5.sp,
                            lineHeight = 16.sp,
                            color = Color(0xFFDCD6F7),
                            textAlign = TextAlign.Center,
                            modifier = Modifier.padding(horizontal = 4.dp)
                        )
                        
                        Spacer(modifier = Modifier.height(14.dp))
                        
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            OutlinedButton(
                                onClick = {
                                    try {
                                        if (trackItem.previewUrl.orEmpty().isNotBlank()) {
                                            viewModel.stopMusicPlayback()
                                            viewModel.playMusicTrack(currentlyPlayingTrack, trackItem.previewUrl ?: "")
                                        } else {
                                            viewModel.playMusicTrackOnTheFly(currentlyPlayingTrack)
                                        }
                                    } catch(e: Exception) {
                                        android.util.Log.e("AuraPlayback", "Re-sync fail: ${e.message}")
                                    }
                                },
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.weight(1.1f),
                                border = BorderStroke(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.8f)),
                                colors = ButtonDefaults.outlinedButtonColors(contentColor = Color(0xFFB388FF))
                            ) {
                                Icon(Icons.Default.Refresh, null, modifier = Modifier.size(13.dp))
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Re-Sync", fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }

                            Button(
                                onClick = {
                                    try {
                                        val targetUrl = if (trackItem.previewUrl.orEmpty().isNotBlank()) {
                                            trackItem.previewUrl.orEmpty()
                                        } else {
                                            "https://music.youtube.com"
                                        }
                                        var finalTarget = targetUrl.replace("www.youtube.com", "music.youtube.com").replace("m.youtube.com", "music.youtube.com")
                                        if (finalTarget.contains("youtu.be/")) {
                                            val id = finalTarget.substringAfter("youtu.be/").substringBefore("?").substringBefore("&")
                                            finalTarget = "https://music.youtube.com/watch?v=$id"
                                        }
                                        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(finalTarget)).apply {
                                            setPackage("com.google.android.apps.youtube.music")
                                            addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                        }
                                        context.startActivity(intent)
                                    } catch(e: Exception) {
                                        val targetUrl = if (trackItem.previewUrl.orEmpty().isNotBlank()) {
                                            trackItem.previewUrl.orEmpty()
                                        } else {
                                            "https://music.youtube.com"
                                        }
                                        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(targetUrl)).apply {
                                            addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                        }
                                        context.startActivity(intent)
                                    }
                                },
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.weight(1.3f),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF7C4DFF))
                            ) {
                                Icon(Icons.Default.Launch, null, modifier = Modifier.size(13.dp), tint = Color.White)
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Open YT Music", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun NotificationsTab(
    state: AuraUiState,
    viewModel: AuraViewModel
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val notifications = remember {
        mutableStateListOf<NotificationItem>()
    }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
            .testTag("notifications_tab"),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        item {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column {
                    Text(
                        text = "Notifications",
                        color = Color.Black,
                        fontSize = 24.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Text(
                        text = "Stay updated with your social aura network",
                        color = Color.Gray,
                        fontSize = 12.sp
                    )
                }

                if (notifications.any { it.isUnread }) {
                    TextButton(
                        onClick = {
                            for (i in notifications.indices) {
                                notifications[i] = notifications[i].copy(isUnread = false)
                            }
                        },
                        colors = ButtonDefaults.textButtonColors(contentColor = LavenderPrimary),
                        modifier = Modifier
                            .clip(RoundedCornerShape(12.dp))
                            .background(Color(0xFFF3E8FF)), // Cute soft bold-lavender accent background
                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp)
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.Center
                        ) {
                            Icon(
                                imageVector = Icons.Default.DoneAll,
                                contentDescription = "Mark all read icon",
                                tint = LavenderPrimary,
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = "Mark all read",
                                color = LavenderPrimary,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.ExtraBold
                            )
                        }
                    }
                }
            }
            Spacer(modifier = Modifier.height(12.dp))
            Divider(color = Color(0xFFF0F2F5))
        }

        if (notifications.isEmpty()) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 60.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            imageVector = Icons.Default.Notifications,
                            contentDescription = "No Notifications",
                            tint = Color.LightGray,
                            modifier = Modifier.size(64.dp)
                        )
                        Spacer(modifier = Modifier.height(12.dp))
                        Text(
                            text = "No notifications yet",
                            color = Color.Gray,
                            fontSize = 15.sp,
                            fontWeight = FontWeight.Medium
                        )
                    }
                }
            }
        } else {
            items(notifications, key = { it.id }) { item ->
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable {
                            val idx = notifications.indexOfFirst { it.id == item.id }
                            if (idx != -1) {
                                notifications[idx] = notifications[idx].copy(isUnread = false)
                            }
                        },
                    shape = RoundedCornerShape(12.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = if (item.isUnread) Color(0xFFF3E8FF).copy(alpha = 0.5f) else Color(0xFFF8FAFC)
                    ),
                    border = BorderStroke(
                        width = 1.dp,
                        color = if (item.isUnread) LavenderPrimary.copy(alpha = 0.3f) else Color(0xFFE2E8F0)
                    )
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(modifier = Modifier.size(44.dp)) {
                            if (item.avatar == "security_shield") {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(Color(0xFFE0F2FE), CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Security,
                                        contentDescription = "Security Status",
                                        tint = Color(0xFF0284C7),
                                        modifier = Modifier.size(24.dp)
                                    )
                                }
                            } else {
                                ProfileAvatar(
                                    avatarId = item.avatar,
                                    size = 44,
                                    fallbackName = item.sender
                                )
                            }
                            
                            if (item.isUnread) {
                                Box(
                                    modifier = Modifier
                                        .size(10.dp)
                                        .background(Color(0xFFFFB300), CircleShape)
                                        .align(Alignment.TopEnd)
                                        .border(1.5.dp, Color.White, CircleShape)
                                )
                            }
                        }

                        Spacer(modifier = Modifier.width(12.dp))

                        Column(modifier = Modifier.weight(1f)) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text(
                                    text = item.sender,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp,
                                    color = Color.Black
                                )
                                Spacer(modifier = Modifier.width(4.dp))
                                Text(
                                    text = "• " + item.time,
                                    color = Color.Gray,
                                    fontSize = 11.sp
                                )
                            }
                            Text(
                                text = item.message,
                                fontSize = 13.sp,
                                color = Color.DarkGray,
                                lineHeight = 18.sp
                            )
                        }

                        IconButton(
                            onClick = {
                                notifications.removeIf { it.id == item.id }
                            },
                            modifier = Modifier.size(24.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Dismiss",
                                tint = Color.LightGray,
                                modifier = Modifier.size(16.dp)
                            )
                        }
                    }
                }
            }
        }
    }
}

data class NotificationItem(
    val id: Int,
    val sender: String,
    val message: String,
    val time: String,
    val avatar: String,
    val isUnread: Boolean
)

// --- SUB-TABS: FEEDS Tab inside Main Platform ---
@Composable
fun FeedsTab(
    state: AuraUiState,
    viewModel: AuraViewModel,
    currentUser: UserEntity?,
    lazyListState: androidx.compose.foundation.lazy.LazyListState = androidx.compose.foundation.lazy.rememberLazyListState()
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val storiesList by viewModel.stories.collectAsStateWithLifecycle()
    val activeStories = remember(storiesList) {
        val twentyFourHoursAgo = System.currentTimeMillis() - (24L * 60 * 60 * 1000)
        val filtered = storiesList.filter { it.timestamp >= twentyFourHoursAgo }
        val grouped = filtered.groupBy { it.authorName.trim().lowercase() }
        grouped.map { (_, list) ->
            val sortedList = list.sortedBy { it.timestamp }
            val representative = sortedList.first()
            val maxTimestampInDeck = list.maxOf { it.timestamp }
            representative to maxTimestampInDeck
        }.sortedByDescending { it.second }
         .map { it.first }
    }
    val postsList by viewModel.postsFeed.collectAsStateWithLifecycle()

    var postIdSearchQuery by remember { mutableStateOf("") }
    val displayedPosts = remember(postsList, postIdSearchQuery) {
        val query = postIdSearchQuery.trim()
        if (query.isBlank()) {
            postsList
        } else {
            postsList.filter { post ->
                val authorUid = viewModel.getUserResolvedUid(post.authorId)
                val cardPostId = "${authorUid}_${post.postId}"
                
                val parts = query.split('_', '-', ' ')
                val isPreciseMatch = if (parts.size >= 2) {
                    val potentialPostId = parts.lastOrNull()?.toIntOrNull()
                    val potentialUid = parts.firstOrNull() ?: ""
                    if (potentialPostId != null && potentialUid.isNotBlank()) {
                        post.postId == potentialPostId && authorUid.equals(potentialUid, ignoreCase = true)
                    } else {
                        false
                    }
                } else {
                    false
                }
                
                isPreciseMatch ||
                cardPostId.equals(query, ignoreCase = true) ||
                post.postId.toString() == query ||
                post.content.contains(query, ignoreCase = true) ||
                post.authorName.contains(query, ignoreCase = true)
            }
        }
    }

    var quickPostText by remember { mutableStateOf("") }
    var quickPostImage by remember { mutableStateOf("") }
    var showAttachImageDialog by remember { mutableStateOf(false) }

    // Dialog for custom image URL attachments (with beautiful presets)
    if (showAttachImageDialog) {
        AlertDialog(
            onDismissRequest = { showAttachImageDialog = false },
            title = { 
                Text(
                    text = "Attach Photo", 
                    fontWeight = FontWeight.ExtraBold, 
                    color = LavenderPrimary,
                    fontSize = 18.sp
                ) 
            },
            text = {
                Column {
                    Text(
                        text = "Enter any high-resolution web URL, or choose an elegant theme backdrop from below:", 
                        fontSize = 12.sp, 
                        color = Color.DarkGray
                    )
                    Spacer(modifier = Modifier.height(12.dp))
                    TextField(
                        value = quickPostImage,
                        onValueChange = { quickPostImage = it },
                        placeholder = { Text("https://images.unsplash.com/photo-...") },
                        singleLine = true,
                        colors = TextFieldDefaults.colors(
                            focusedIndicatorColor = LavenderPrimary,
                            focusedContainerColor = Color(0xFFF5F5F5),
                            unfocusedContainerColor = Color(0xFFF5F5F5)
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(
                        text = "Stunning Backdrops:", 
                        fontWeight = FontWeight.Bold, 
                        fontSize = 12.sp,
                        color = Color.Black
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        val presets = listOf(
                            "Nature" to "https://images.unsplash.com/photo-1542224566-6e85f2e6772f?w=600",
                            "Vibrant Gradient" to "https://images.unsplash.com/photo-1550684848-fac1c5b4e853?w=600",
                            "Abstract Dream" to "https://images.unsplash.com/photo-1511447333015-45b65e60f6d5?w=600"
                        )
                        presets.forEach { (name, url) ->
                            val isChosen = quickPostImage == url
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                        .height(55.dp)
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(if (isChosen) LavenderPrimary.copy(alpha = 0.15f) else Color(0xFFF5F5F5))
                                        .border(1.5.dp, if (isChosen) LavenderPrimary else Color.Transparent, RoundedCornerShape(8.dp))
                                        .clickable { quickPostImage = url }
                                        .padding(4.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = name, 
                                    fontSize = 10.sp, 
                                    fontWeight = FontWeight.Bold, 
                                    textAlign = TextAlign.Center, 
                                    color = if (isChosen) LavenderPrimary else Color.DarkGray
                                )
                            }
                        }
                    }
                }
            },
            confirmButton = {
                Button(
                    onClick = { showAttachImageDialog = false },
                    colors = ButtonDefaults.buttonColors(containerColor = LavenderPrimary)
                ) {
                    Text("Attach", color = Color.White, fontWeight = FontWeight.Bold)
