                                    color = Color(0xFF4C1D95),
                                    fontSize = 13.sp
                                )
                            }
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = "আপনি বর্তমানে গেস্ট মোডে আছেন। ওড়া অ্যাপের সকল ফিচার যেমন ওড়া ম্যাচিং ও ভাইব চেক, পোস্ট ক্রিয়েশন, চ্যাট করা, ফ্রেন্ড রিকোয়েস্ট পাঠানো এবং পোস্টে লাইক ও কমেন্ট করার চমৎকার অভিজ্ঞতা উপভোগ করতে দয়া করে নিচের Discord বাটনে ক্লিক করে রেজিস্টার করুন! 💜✨",
                            fontSize = 12.sp,
