                                .height(48.dp)
                                .shadow(2.dp, RoundedCornerShape(12.dp))
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.Center
                            ) {
                                DiscordLogoIcon(modifier = Modifier.size(18.dp), isBlurpleBackground = true)
                                Spacer(modifier = Modifier.width(8.dp))
                                Text(
                                    text = "Sign up with Discord",
                                    color = Color.White,
                                    fontSize = 13.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }
            }
        }

        // Step 1: Facebook-style "What's on your mind?" composer bar
        if (!state.isViewingAsGuest) {
            item {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.White)
                        .padding(top = 12.dp, bottom = 8.dp)
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 16.dp, vertical = 4.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        // Profile Avatar - Clickable to PROFILE tab
                        Box(
                            modifier = Modifier
