                        }
                        
                        Spacer(modifier = Modifier.width(12.dp))
                        
                        // "What's on your mind?" Box - Clickable to CREATE_POST tab
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .height(44.dp)
                                .background(Color(0xFFF0F2F5), RoundedCornerShape(22.dp))
                                .clickable {
