                    }
                    
                    Spacer(modifier = Modifier.height(10.dp))
                    Divider(color = Color(0xFFF0F2F5), thickness = 6.dp)
                }
            }
        }

        // Step 2: Horizontal Stories bar (9:16 layout) exactly matching screenshot specifications
        item {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color.White)
