                LazyRow(
                    contentPadding = PaddingValues(horizontal = 16.dp),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    // Card 1: Beautiful Music Story Card (Accurate to second screenshot)
                    item {
                        Box(
                            modifier = Modifier
                                .width(100.dp)
                                .aspectRatio(9f / 16f)
                                .clip(RoundedCornerShape(14.dp))
                                .background(
                                    Brush.verticalGradient(
                                        colors = listOf(Color(0xFF2EF1C7), Color(0xFF1596EC))
                                    )
                                )
                                .clickable {
                                    viewModel.setAUMusicGeneratorVisible(true)
                                }
                        ) {
                            Column(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .padding(8.dp),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.SpaceBetween
                            ) {
                                Spacer(modifier = Modifier.height(10.dp))
                                
                                // Centered Music circular white card icon
                                Box(
                                    modifier = Modifier
                                        .size(38.dp)
                                        .background(Color.White, CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.MusicVideo, 
                                        contentDescription = "Create story with Aura AI music", 
                                        tint = Color(0xFF1596EC),
                                        modifier = Modifier.size(22.dp)
                                    )
                                }
                                
                                Text(
                                    text = "Create story with Aura AI music",
                                    color = Color.White,
                                    fontSize = 8.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    textAlign = TextAlign.Center,
