                                }

                                // Beautiful speech-bubble for live notes! Overlaps the top center of the story card beautifully.
                                if (state.activeUserNote.isNotBlank()) {
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.TopCenter)
                                            .padding(top = 8.dp, start = 4.dp, end = 4.dp)
