                                            fontSize = 13.sp,
                                            color = Color(0xFF7C4DFF)
                                        )
                                    }

                                    Spacer(modifier = Modifier.height(10.dp))

                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .background(Color.White.copy(alpha = 0.9f), RoundedCornerShape(12.dp))
