                                        }

                                        // Match Score Bubble
                                        Column(
                                            horizontalAlignment = Alignment.CenterHorizontally,
                                            modifier = Modifier.weight(1.2f)
                                        ) {
                                            Text(
                                                text = "$score%",
                                                fontSize = 22.sp,
                                                fontWeight = FontWeight.Black,
