                                            )
                                            Text(
                                                text = "Compatibility Score",
                                                fontSize = 8.sp,
                                                color = Color.DarkGray,
                                                fontWeight = FontWeight.Bold
                                            )
                                            Spacer(modifier = Modifier.height(4.dp))
                                            Text(
                                                text = titleText,
                                                fontSize = 9.sp,
                                                fontWeight = FontWeight.Bold,
                                                color = Color.White,
                                                modifier = Modifier
                                                    .background(vibeColor, RoundedCornerShape(6.dp))
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            )
                                        }

                                        // Checked Partner
                                        Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.weight(0.9f)) {
                                            ProfileAvatar(
                                                avatarId = "avatar_p2p_streamer",
                                                size = 40,
                                                fallbackName = partnerName
                                            )
                                            Spacer(modifier = Modifier.height(4.dp))
                                            Text(
                                                text = partnerName.split(" ").firstOrNull() ?: partnerName,
                                                fontSize = 10.sp,
                                                fontWeight = FontWeight.Bold,
                                                color = Color.Black
                                            )
                                        }
                                    }

                                    Spacer(modifier = Modifier.height(8.dp))
                                    Text(
                                        text = "“$adviceText”",
                                        fontSize = 11.sp,
                                        fontStyle = androidx.compose.ui.text.font.FontStyle.Italic,
                                        color = Color.DarkGray,
                                        textAlign = TextAlign.Center,
                                        modifier = Modifier.fillMaxWidth().padding(horizontal = 4.dp)
                                    )
                                }
                            }
                        }
                    }

                    // Multi-image Collage rendering with click to view full screen as requested
                    val isUrlValid = post.imageUrl.isNotBlank() && (
                        post.imageUrl.contains("/") ||
                        post.imageUrl.startsWith("http", ignoreCase = true) ||
                        post.imageUrl.startsWith("content", ignoreCase = true)
                    )
                    if (isUrlValid) {
                        var activeFullImageViewerIndex by remember { mutableStateOf<Int?>(null) }
                        
                        PostCollage(
                            imageUrlString = post.imageUrl,
                            post = post,
                            viewModel = viewModel,
                            onImageClick = { index ->
                                activeFullImageViewerIndex = index
                            }
                        )

                        activeFullImageViewerIndex?.let { index ->
                            FullScreenImageViewer(
                                imageUrls = post.imageUrl.split(",").filter { it.isNotBlank() },
                                initialIndex = index,
                                post = post,
                                viewModel = viewModel,
