                                // Download Icon Top Right
                                IconButton(
                                    onClick = {
                                        val scope = kotlinx.coroutines.CoroutineScope(kotlinx.coroutines.Dispatchers.IO)
                                        scope.launch {
                                            try {
                                                val destFileName = "Aura_GIF_${System.currentTimeMillis()}.gif"
                                                val downloadsFolder = android.os.Environment.getExternalStoragePublicDirectory(android.os.Environment.DIRECTORY_DOWNLOADS)
                                                if (!downloadsFolder.exists()) downloadsFolder.mkdirs()
                                                val dstFile = java.io.File(downloadsFolder, destFileName)
                                                
                                                val conn = java.net.URL(post.gifUrl).openConnection() as java.net.HttpURLConnection
                                                conn.connectTimeout = 8000
                                                conn.readTimeout = 8000
                                                conn.connect()
                                                if (conn.responseCode == java.net.HttpURLConnection.HTTP_OK) {
                                                    val input = conn.inputStream
                                                    val output = java.io.FileOutputStream(dstFile)
                                                    val buffer = ByteArray(4096)
                                                    var count: Int
                                                    while (input.read(buffer).also { count = it } != -1) {
                                                        output.write(buffer, 0, count)
                                                    }
                                                    output.close()
                                                    input.close()
                                                    
                                                    android.media.MediaScannerConnection.scanFile(
                                                        context,
                                                        arrayOf(dstFile.absolutePath),
                                                        arrayOf("image/gif"),
                                                        null
                                                    )
                                                    
                                                    kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                                        android.widget.Toast.makeText(context, "GIF downloaded successfully! Saved in Downloads folder 📁🎉", android.widget.Toast.LENGTH_LONG).show()
                                                    }
                                                } else {
                                                    throw Exception("HTTP " + conn.responseCode)
                                                }
                                            } catch (e: Exception) {
