                                            fontWeight = FontWeight.Bold
                                        )
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Text(
                                            text = "You're friends with ${post.authorName}",
                                            color = Color.White,
                                            fontSize = 15.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }

                            // Group 1: Interested / Not interested
                            item {
                                Card(
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                ) {
                                    Column {
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.AddCircle,
                                            title = "Interested",
                                            subtitle = "More of your posts will be like this.",
                                            onClick = { 
                                                showMenuSheet = false
                                                android.widget.Toast.makeText(context, "More of your posts will be like this", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                        Divider(color = Color.Gray.copy(alpha = 0.2f))
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.RemoveCircle,
                                            title = "Not interested",
                                            subtitle = "Less of your posts will be like this.",
                                            onClick = { 
                                                showMenuSheet = false
                                                android.widget.Toast.makeText(context, "Less of your posts will be like this", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                    }
                                }
                            }

                            // Group 2: Save, Hide, Notifs
                            item {
                                Card(
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                ) {
                                    Column {
                                        val isCurrentlySaved = post.isSavedByUser
                                        BottomSheetOptionRow(
                                            icon = if (isCurrentlySaved) Icons.Default.Bookmark else Icons.Default.BookmarkBorder,
                                            title = if (isCurrentlySaved) "Unsave post" else "Save post",
                                            subtitle = if (isCurrentlySaved) "Remove this from your saved items." else "Add this to your saved items.",
                                            onClick = { 
                                                showMenuSheet = false
                                                viewModel.togglePostSave(post)
                                                if (isCurrentlySaved) {
                                                    android.widget.Toast.makeText(context, "Post removed from saved items", android.widget.Toast.LENGTH_LONG).show()
                                                } else {
                                                    android.widget.Toast.makeText(context, "Add this to your saved items", android.widget.Toast.LENGTH_LONG).show()
                                                }
                                            }
                                        )
                                        Divider(color = Color.Gray.copy(alpha = 0.2f))
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.VisibilityOff,
                                            title = "Hide post",
                                            subtitle = "See fewer posts like this.",
                                            onClick = { 
                                                showMenuSheet = false
                                                viewModel.deletePost(post.postId)
                                                android.widget.Toast.makeText(context, "See fewer posts like this", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                        Divider(color = Color.Gray.copy(alpha = 0.2f))
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.Notifications,
                                            title = "Turn on notifications for this post",
                                            onClick = { 
                                                showMenuSheet = false
                                                android.widget.Toast.makeText(context, "Turned on notifications for this post", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                    }
                                }
                            }

                            // Group 3: Favorites, Snooze, Unfollow
                            item {
                                Card(
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                ) {
                                    Column {
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.Star,
                                            title = "Add ${post.authorName} to Favorites",
                                            subtitle = "Prioritize his posts in News Feed.",
                                            onClick = { 
                                                showMenuSheet = false
                                                android.widget.Toast.makeText(context, "Prioritize his posts in News Feed", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                        Divider(color = Color.Gray.copy(alpha = 0.2f))
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.AccessTime,
                                            title = "Snooze ${post.authorName} for 30 days",
                                            subtitle = "Temporarily stop seeing posts.",
                                            onClick = { 
                                                showMenuSheet = false
                                                viewModel.deletePost(post.postId)
                                                android.widget.Toast.makeText(context, "Temporarily stop seeing posts", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                        Divider(color = Color.Gray.copy(alpha = 0.2f))
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.PersonOutline,
                                            title = "Unfollow ${post.authorName}",
                                            subtitle = "Stop seeing posts but stay friends. They won't be notified that you unfollowed...",
                                            onClick = { 
                                                showMenuSheet = false
                                                viewModel.deletePost(post.postId)
                                                android.widget.Toast.makeText(context, "Stop seeing posts but stay friends. They won't be notified that you unfollowed...", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                    }
                                }
                            }

                            // Group 4: Block
                            item {
                                Card(
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                ) {
                                    Column {
                                        BottomSheetOptionRow(
                                            icon = Icons.Default.Block,
                                            title = "Block ${post.authorName}'s profile",
                                            subtitle = "You won't be able to see or contact each other.",
                                            onClick = { 
                                                showMenuSheet = false
                                                viewModel.deletePost(post.postId)
                                                android.widget.Toast.makeText(context, "You won't be able to see or contact each other", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        )
                                    }
                                }
                            }

                            item {
                                Spacer(modifier = Modifier.height(24.dp))
                            }
                        }
                    }
                }
            }
        }
    }

    if (showReactionsBottomSheet) {
        androidx.compose.ui.window.Dialog(
            onDismissRequest = { showReactionsBottomSheet = false },
            properties = androidx.compose.ui.window.DialogProperties(
                usePlatformDefaultWidth = false
            )
        ) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(Color.Black.copy(alpha = 0.5f))
                    .clickable { showReactionsBottomSheet = false },
                contentAlignment = Alignment.BottomCenter
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 480.dp)
                        .clip(RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp))
                        .background(Color.White)
                        .padding(16.dp)
                        .clickable(enabled = false) {}
                ) {
                    Box(
                        modifier = Modifier
                            .size(40.dp, 4.dp)
                            .clip(RoundedCornerShape(2.dp))
                            .background(Color.LightGray)
                            .align(Alignment.CenterHorizontally)
                    )
                    
                    Spacer(modifier = Modifier.height(12.dp))
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "পোস্ট রিঅ্যাকশন সমূহ (Post Reactions)",
                            color = Color(0xFF7C4DFF),
                            fontSize = 17.sp,
                            fontWeight = FontWeight.Bold
                        )
                        
                        IconButton(onClick = { showReactionsBottomSheet = false }) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close description",
                                tint = Color.Gray,
                                modifier = Modifier.size(24.dp)
                            )
                        }
                    }
                    
                    Spacer(modifier = Modifier.height(10.dp))
                    Divider(color = Color.LightGray.copy(alpha = 0.5f))
                    Spacer(modifier = Modifier.height(8.dp))
                    
                    if (reactions.isEmpty()) {
                        Box(
                            modifier = Modifier.fillMaxWidth().height(180.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                "এখনো কোনো রিঅ্যাকশন দেওয়া হয়নি! প্রথম রিঅ্যাকশন দিন 💜",
                                color = Color.Gray,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Medium
                            )
                        }
                    } else {
                        LazyColumn(
                            modifier = Modifier.fillMaxWidth().weight(1f),
                            verticalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            items(reactions) { reaction ->
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(vertical = 4.dp),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Box(
                                            modifier = Modifier.size(42.dp),
                                            contentAlignment = Alignment.BottomEnd
                                        ) {
                                            ProfileAvatar(
                                                avatarId = reaction.userAvatar,
                                                fallbackName = reaction.userName,
                                                modifier = Modifier
                                                    .fillMaxSize()
                                                    .clip(CircleShape)
                                                    .border(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.2f), CircleShape)
                                            )
                                            Box(
                                                modifier = Modifier
                                                    .size(16.dp)
                                                    .background(Color.White, CircleShape)
                                                    .border(0.5.dp, Color(0xFF7C4DFF), CircleShape),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text(reaction.emoji, fontSize = 9.sp)
                                            }
                                        }
                                        Spacer(modifier = Modifier.width(12.dp))
                                        Column {
                                            Text(
                                                text = reaction.userName,
                                                color = Color.Black,
                                                fontSize = 14.sp,
                                                fontWeight = FontWeight.SemiBold
                                            )
                                            Text(
                                                text = reaction.userEmail,
                                                color = Color.Gray,
                                                fontSize = 11.sp
                                            )
                                        }
                                    }
                                    
                                    Text(
                                        text = reaction.emoji,
                                        fontSize = 24.sp
                                    )
                                }
                                Divider(color = Color.LightGray.copy(alpha = 0.3f), thickness = 0.5.dp)
                            }
                        }
                    }
                }
            }
        }
    }
}

data class ViewerInfo(
    val userId: Int,
    val displayName: String,
    val avatarUrl: String,
    val emoji: String
)

// --- SHARED POPUP LAYER: STORIES VIEWER MODAL (FULL SCREEN INTERACTION DECK) ---
@Composable
fun StoryViewerModal(
    story: StoryEntity,
    viewModel: AuraViewModel
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val state by viewModel.uiState.collectAsStateWithLifecycle()
    val storiesList by viewModel.stories.collectAsStateWithLifecycle()
    val allUsersList by viewModel.allUsers.collectAsStateWithLifecycle()
    val currentUser by viewModel.currentUser.collectAsStateWithLifecycle()

    val twentyFourHoursAgo = remember { System.currentTimeMillis() - (24L * 60 * 60 * 1000) }
    val unexpiredStories = remember(storiesList) { 
        storiesList.filter { it.timestamp >= twentyFourHoursAgo } 
    }
    val groupedByUser = remember(unexpiredStories) { 
        unexpiredStories.groupBy { it.authorName } 
    }
    val usersWithStories = remember(groupedByUser) { 
        groupedByUser.keys.toList() 
    }

    var currentUserIndex by remember(story.authorName) { 
        val idx = usersWithStories.indexOfFirst { it.trim().equals(story.authorName.trim(), ignoreCase = true) }
        mutableStateOf(if (idx != -1) idx else 0)
    }

    if (usersWithStories.isEmpty() || currentUserIndex !in usersWithStories.indices) {
        Box(
            modifier = Modifier.fillMaxSize().background(Color.Black),
            contentAlignment = Alignment.Center
        ) {
            Text("No Active Stories Found", color = Color.White)
        }
        return
    }

    val currentAuthorName = usersWithStories[currentUserIndex]
    val authorUserEntity = remember(allUsersList, currentAuthorName) {
        allUsersList.find { it.displayName == currentAuthorName }
    }

    // Lock check logic: A user cannot view a locked profile's stories unless they are friends.
    val localCurrentUser = currentUser
    val isFriend = remember(authorUserEntity, localCurrentUser) {
        if (authorUserEntity == null || localCurrentUser == null) false
        else if (authorUserEntity.userId == localCurrentUser.userId) true
        else {
            val sharedPrefs = context.getSharedPreferences("aura_friend_relations", android.content.Context.MODE_PRIVATE)
            sharedPrefs.getBoolean("friend_${authorUserEntity.userId}", false)
        }
    }
    val isLocked = authorUserEntity?.isProfileLocked == true
    val isBlocked = remember(authorUserEntity) {
        if (authorUserEntity == null) false
        else {
            val sharedPrefs = context.getSharedPreferences("aura_friend_relations", android.content.Context.MODE_PRIVATE)
            sharedPrefs.getBoolean("blocked_${authorUserEntity.userId}", false)
        }
    }
    val isOwn = localCurrentUser?.displayName == currentAuthorName
    val isRestricted = isLocked && !isFriend && !isBlocked && !isOwn

    // Compute steps for the current user sequence
    val authorStories = remember(groupedByUser, currentAuthorName) {
        groupedByUser[currentAuthorName] ?: emptyList()
    }

    data class ViewerStep(val story: StoryEntity, val mediaUrl: String?)
    val steps = remember(authorStories) {
        authorStories.flatMap { storyItem ->
            val urls = storyItem.imageUrl.split(",").filter { it.isNotBlank() }
            if (urls.isEmpty()) {
                listOf(ViewerStep(storyItem, null))
            } else {
                urls.map { ViewerStep(storyItem, it) }
            }
        }
    }

    var currentStepIndex by remember(currentUserIndex) { mutableStateOf(0) }
    var progress by remember(currentUserIndex, currentStepIndex) { mutableStateOf(0f) }
    var isPaused by remember { mutableStateOf(false) }
    var showViewersSheet by remember { mutableStateOf(false) }
    val storyViewerScope = rememberCoroutineScope()

    // Register story view when loaded
    LaunchedEffect(currentUserIndex, currentStepIndex) {
        val stepItem = steps.getOrNull(currentStepIndex)
        if (stepItem != null) {
            viewModel.registerStoryView(stepItem.story.storyId, currentStepIndex)
        }
    }

    val viewersForStep = remember(currentStepIndex, currentUserIndex, steps) {
        val currentStepItem = steps.getOrNull(currentStepIndex)
        if (currentStepItem == null) {
            emptyList<ViewerInfo>()
        } else {
            val viewersStr = currentStepItem.story.viewersJson
            if (viewersStr.isBlank()) {
                emptyList<ViewerInfo>()
            } else {
                viewersStr.split(";").mapNotNull { part ->
                    // part is either "stepIndex:displayName|avatarUrl|emoji" or "displayName|avatarUrl|emoji"
                    val stepAndContent = part.split(":", limit = 2)
                    val (stepIdx, content) = if (stepAndContent.size == 2) {
                        val sIdx = stepAndContent[0].toIntOrNull() ?: 0
                        sIdx to stepAndContent[1]
                    } else {
                        0 to part
                    }
                    
                    // Only show viewer if stepIdx matches currentStepIndex
                    if (stepIdx == currentStepIndex) {
                        val subParts = content.split("|")
                        if (subParts.size >= 2) {
                            val name = subParts[0]
                            val avatar = subParts[1]
                            val emoji = subParts.getOrNull(2) ?: ""
                            ViewerInfo(
                                userId = name.hashCode(),
                                displayName = name,
                                avatarUrl = avatar,
                                emoji = emoji
                            )
                        } else null
                    } else null
                }.sortedWith(compareByDescending { it.emoji.isNotBlank() })
            }
        }
    }

    // Dynamic video duration tracker
    var currentVideoDuration by remember(currentUserIndex, currentStepIndex) { mutableStateOf<Float?>(null) }

    // Control loops for playback
    val currentStep = steps.getOrNull(currentStepIndex)
    val isVideo = remember(currentStepIndex, currentUserIndex) {
        val path = currentStep?.mediaUrl
        path != null && isVideoPath(path)
    }

    LaunchedEffect(currentUserIndex, currentStepIndex, isPaused, isRestricted, currentVideoDuration) {
        if (isRestricted || isPaused) return@LaunchedEffect
        val durationMs = if (isVideo) {
            currentVideoDuration ?: 5000f
        } else {
            5000f
        }
        val intervalMs = 25f
        while (progress < 1.0f) {
            kotlinx.coroutines.delay(intervalMs.toLong())
            if (!isPaused) {
                progress += intervalMs / durationMs
            }
        }
        // Completed step
        if (currentStepIndex < steps.size - 1) {
            currentStepIndex++
            progress = 0f
            currentVideoDuration = null
        } else {
            // Next user
            if (currentUserIndex < usersWithStories.size - 1) {
                currentUserIndex++
                progress = 0f
                currentVideoDuration = null
            } else {
                viewModel.showStory(null)
            }
        }
    }

    // Swipe offset accumulator
    var dragOffsetX by remember { mutableStateOf(0f) }

    // Floating emoji response list
    var floatingEmojis by remember { mutableStateOf(emptyList<FloatingEmoji>()) }
    LaunchedEffect(floatingEmojis) {
        if (floatingEmojis.isNotEmpty()) {
            kotlinx.coroutines.delay(16)
            floatingEmojis = floatingEmojis.map { 
                it.copy(yOffset = it.yOffset - 5f) 
            }.filter { it.yOffset > -400f }
        }
    }

    fun triggerBurstEmojis(emoji: String) {
        val count = (6..10).random()
        val list = (1..count).map {
            FloatingEmoji(
                id = System.nanoTime() + (0..9999).random(),
                emoji = emoji,
                xOffset = (-80..80).random().toFloat(),
                yOffset = (-50..-10).random().toFloat()
            )
        }
        floatingEmojis = floatingEmojis + list
    }

    // Direct message / reply input text
    var replyMessageInput by remember { mutableStateOf("") }

    val storyScale by androidx.compose.animation.core.animateFloatAsState(targetValue = if (showViewersSheet) 0.88f else 1.0f)
    val storyOffsetY by androidx.compose.animation.core.animateDpAsState(targetValue = if (showViewersSheet) (-90).dp else 0.dp)

    // System-level full-screen overlay container
    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.Black)
            .testTag("story_viewer_modal")
            .pointerInput(currentUserIndex) {
                detectHorizontalDragGestures(
                    onDragEnd = {
                        if (dragOffsetX < -120f) {
                            // Swipe Left -> Next user
                            if (currentUserIndex < usersWithStories.size - 1) {
                                currentUserIndex++
                            } else {
                                viewModel.showStory(null)
                            }
                        } else if (dragOffsetX > 120f) {
                            // Swipe Right -> Prev user
                            if (currentUserIndex > 0) {
                                currentUserIndex--
                            }
                        }
                        dragOffsetX = 0f
                    },
                    onHorizontalDrag = { change: androidx.compose.ui.input.pointer.PointerInputChange, dragAmount: Float ->
                        dragOffsetX += dragAmount
                    }
                )
            }
    ) {
        if (isRestricted) {
            // Privacy lock shield state display
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(32.dp),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Icon(
                    imageVector = Icons.Default.Lock,
                    contentDescription = "Lock Shield Indicator",
                    tint = Color.White,
                    modifier = Modifier.size(64.dp)
                )
                Spacer(modifier = Modifier.height(16.dp))
                Text(
                    text = "This Account is Locked 🔒",
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold,
                    color = Color.White
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = "Aura stories from @$currentAuthorName are private.\nAdd them as a friend to view their amazing story!",
                    fontSize = 13.sp,
                    color = Color.LightGray,
                    textAlign = TextAlign.Center
                )
                Spacer(modifier = Modifier.height(24.dp))
                Button(
                    onClick = { viewModel.showStory(null) },
                    colors = ButtonDefaults.buttonColors(containerColor = LavenderPrimary)
                ) {
                    Text("Go Back", color = Color.White)
                }
            }
        } else {
            // Safe current step extraction
            val currentStep = steps.getOrNull(currentStepIndex)
            if (currentStep != null) {
                // Background visual backdrop: either crop media or premium gradient
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .graphicsLayer {
                            scaleX = storyScale
                            scaleY = storyScale
                            translationY = storyOffsetY.toPx()
                        }
                        .clip(RoundedCornerShape(if (showViewersSheet) 16.dp else 0.dp))
                        .pointerInput(currentStepIndex, currentUserIndex) {
                            detectTapGestures(
                                onPress = {
                                    isPaused = true
                                    try {
                                        this.awaitRelease()
                                    } finally {
                                        isPaused = false
                                    }
                                },
                                onTap = { position: androidx.compose.ui.geometry.Offset ->
                                    val screenWidth = size.width
                                    if (position.x < screenWidth * 0.35f) {
                                        // Tap Left -> Prev story
                                        if (currentStepIndex > 0) {
                                            currentStepIndex--
                                            progress = 0f
                                            currentVideoDuration = null
                                        } else {
                                            // Prev user
                                            if (currentUserIndex > 0) {
                                                currentUserIndex--
                                                currentVideoDuration = null
                                            }
                                        }
                                    } else {
                                        // Tap Right -> Next story
                                        if (currentStepIndex < steps.size - 1) {
                                            currentStepIndex++
                                            progress = 0f
                                            currentVideoDuration = null
                                        } else {
                                            // Next user
                                            if (currentUserIndex < usersWithStories.size - 1) {
                                                currentUserIndex++
                                                currentVideoDuration = null
                                            } else {
                                                viewModel.showStory(null)
                                            }
                                        }
                                    }
                                }
                            )
                        }
                ) {
                    if (currentStep.story.gradientIndex in PremiumGradients.indices) {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .background(PremiumGradients[currentStep.story.gradientIndex])
                        )
                    } else {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .background(Color(0xFF1E1B29)) // Ambient dark layout
                        )
                    }

                    val cleanVC = currentStep.story.contentText
                    val isDefaultVC = cleanVC.isNotBlank() && !cleanVC.contains("Sharing amazing Aura", ignoreCase = true)

                    if (currentStep.mediaUrl != null && currentStep.mediaUrl.isNotBlank()) {
                        val isVideoItem = isVideoPath(currentStep.mediaUrl)
                        if (isVideoItem) {
                            AuraVideoPlayer(
                                videoPath = currentStep.mediaUrl,
                                modifier = Modifier.fillMaxSize().align(Alignment.Center),
                                isMute = state.isStoryMuted,
                                isLooping = false,
                                isPaused = isPaused,
                                onVideoDurationReady = { duration ->
                                    currentVideoDuration = duration.toFloat()
                                },
                                onVideoEnded = {
                                    progress = 1.0f
                                }
                            )
                        } else {
                            AsyncImage(
                                model = currentStep.mediaUrl,
                                contentDescription = "Active Story media content",
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                modifier = Modifier.fillMaxSize().align(Alignment.Center)
                            )
                        }
                    }

                    // Ambient dim card overlay (for text readability) - ONLY for photos/text, NOT for videos!
                    val hasVideoContent = currentStep.mediaUrl != null && isVideoPath(currentStep.mediaUrl)
                    if (!hasVideoContent) {
                        if (isDefaultVC) {
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(Color.Black.copy(alpha = 0.3f))
                            )
                        } else {
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(
                                        androidx.compose.ui.graphics.Brush.verticalGradient(
                                            colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.4f))
                                        )
                                    )
                            )
                        }
                    }

                    // Story text title (centered horizontally)
                    if (isDefaultVC) {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(horizontal = 24.dp, vertical = 120.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                text = cleanVC,
                                color = Color.White,
                                fontSize = 24.sp,
                                fontWeight = FontWeight.ExtraBold,
                                textAlign = TextAlign.Center,
                                style = LocalTextStyle.current.copy(
                                    shadow = Shadow(Color.Black.copy(alpha = 0.8f), Offset(2f, 2f), 6f)
                                )
                            )
                        }
                    }

                    // Web Link Pill (if available)
                    if (currentStep.story.websiteUrl.isNotBlank()) {
                        val originalLink = currentStep.story.websiteUrl
                        Box(
                            modifier = Modifier
                                .align(Alignment.BottomCenter)
                                .padding(bottom = 140.dp)
                        ) {
                            Button(
                                onClick = {
                                    try {
                                        val parseUr = if (!originalLink.startsWith("http")) "https://$originalLink" else originalLink
                                        val webIntent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(parseUr))
                                        context.startActivity(webIntent)
                                    } catch (e: Exception) {
                                        android.widget.Toast.makeText(context, "Cannot open link: $originalLink", android.widget.Toast.LENGTH_SHORT).show()
                                    }
                                },
                                colors = ButtonDefaults.buttonColors(containerColor = LavenderPrimary.copy(alpha = 0.85f)),
                                shape = RoundedCornerShape(18.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(Icons.Default.Launch, null, tint = Color.White, modifier = Modifier.size(14.dp))
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text("Visit URL", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }
                }
            }
        }

        // --- OVERLAY GAUGE: DUAL CHANNELS TOP INDICATOR PILLS AND AUDIO CONTROLS etc ---
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 16.dp, start = 14.dp, end = 14.dp)
                .align(Alignment.TopCenter)
        ) {
            // Sequential Progress Indicators
            if (!isRestricted) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 12.dp),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    steps.forEachIndexed { sIdx, _ ->
                        val barProgress = when {
                            sIdx < currentStepIndex -> 1.0f
                            sIdx > currentStepIndex -> 0.0f
                            else -> progress
                        }
                        Box(
                            modifier = Modifier
                                .weight(1f)
                                .height(3.5.dp)
                                .clip(RoundedCornerShape(2.dp))
                                .background(Color.White.copy(alpha = 0.45f))
                        ) {
                            Box(
                                modifier = Modifier
                                    .fillMaxHeight()
                                    .fillMaxWidth(barProgress)
                                    .background(Color.White)
                            )
                        }
                    }
                }
            }

            // Top control row (Author profile info, AI tags and actions)
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                // Left profile metadata trigger with direct dashboard navigation redirection
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier.clickable {
                        viewModel.showStory(null)
                        if (authorUserEntity != null) {
                            viewModel.navigateTo(Screen.ProfileDetail(authorUserEntity))
                        }
                    }
                ) {
                    ProfileAvatar(
                        avatarId = authorUserEntity?.avatarUrl ?: "avatar_default",
                        fallbackName = currentAuthorName,
                        size = 38
                    )
                    Spacer(modifier = Modifier.width(10.dp))
                    Column {
                        Text(
                            text = currentAuthorName,
                            color = Color.White,
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp
                        )
                        // Trigger AI banner conditionally below author metadata
                        val currentStep = steps.getOrNull(currentStepIndex)
                        if (currentStep?.story?.isAiRelated == true) {
                            Text(
                                text = "AI Related ✨",
                                color = Color(0xFFB39DDB),
                                fontWeight = FontWeight.Black,
                                fontSize = 11.sp
                            )
                        }
                    }
                }

                // Control actions (Delete Menu, Volume, Close)
                Row(verticalAlignment = Alignment.CenterVertically) {
                    val currentStep = steps.getOrNull(currentStepIndex)
                    if (currentStep != null && isOwn) {
                        var showThreeDotDelete by remember { mutableStateOf(false) }
                        Box {
                            IconButton(onClick = { showThreeDotDelete = true }) {
                                Icon(Icons.Default.MoreVert, "Settings", tint = Color.White)
                            }
                            DropdownMenu(
                                expanded = showThreeDotDelete,
                                onDismissRequest = { showThreeDotDelete = false }
                            ) {
                                DropdownMenuItem(
                                    text = { Text("Delete permanently 🗑️", color = Color.Red, fontWeight = FontWeight.Bold) },
                                    onClick = {
                                        showThreeDotDelete = false
                                        viewModel.deleteStory(currentStep.story.storyId)
                                        // Auto advance or close with index shift correction
                                        val newStepCount = steps.size - 1
                                        if (newStepCount <= 0) {
                                            if (currentUserIndex < usersWithStories.size - 1) {
                                                currentUserIndex++
                                                currentStepIndex = 0
                                                progress = 0f
                                            } else {
                                                viewModel.showStory(null)
                                            }
                                        } else {
                                            if (currentStepIndex >= newStepCount) {
                                                currentStepIndex = newStepCount - 1
                                                progress = 0f
                                            } else {
                                                progress = 0f
                                            }
                                        }
                                        android.widget.Toast.makeText(context, "Story removed", android.widget.Toast.LENGTH_SHORT).show()
                                    }
                                )
                            }
                        }
                    }

                    // Sound Toggle Icon Control
                    IconButton(onClick = { viewModel.setStoryMuted(!state.isStoryMuted) }) {
                        Icon(
                            imageVector = if (state.isStoryMuted) Icons.Default.VolumeOff else Icons.Default.VolumeUp,
                            contentDescription = "Toggle Mute Status",
                            tint = Color.White
                        )
                    }

                    // Close Button
                    IconButton(onClick = { viewModel.showStory(null) }) {
                        Icon(Icons.Default.Close, "Dismiss Modal", tint = Color.White)
                    }
                }
            }
        }

        // --- BOTTOM DRAWER DECK FOR REACTION EMOJIS AND SENDING DIRECT IN-BOX DM COMMENT REPLIES ---
        if (!isRestricted) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 16.dp, start = 14.dp, end = 14.dp)
                    .align(Alignment.BottomCenter)
            ) {
                // Real-time Story Viewers Horizontal Summary
                Row(
                    modifier = Modifier
                        .padding(bottom = 12.dp)
                        .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(20.dp))
                        .clickable {
                            isPaused = true
                            showViewersSheet = true
                        }
                        .padding(horizontal = 14.dp, vertical = 7.dp)
                        .testTag("story_viewers_trigger"),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Icon(
                        imageVector = Icons.Default.Visibility,
                        contentDescription = "Viewers Count",
                        tint = Color.White,
                        modifier = Modifier.size(16.dp)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(
                        text = "${viewersForStep.size}",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Spacer(modifier = Modifier.width(12.dp))
                    Box(
                        modifier = Modifier
                            .width(1.dp)
                            .height(14.dp)
                            .background(Color.White.copy(alpha = 0.3f))
                    )
                    Spacer(modifier = Modifier.width(12.dp))
                    
                    // Overlapping profile avatars of first 4 viewers
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy((-8).dp)
                    ) {
                        val maxAvatars = minOf(viewersForStep.size, 4)
                        for (i in 0 until maxAvatars) {
                            val v = viewersForStep[i]
                            Box(
                                modifier = Modifier
                                    .size(24.dp)
                                    .clip(CircleShape)
                                    .background(Color.White)
                                    .padding(1.dp)
                            ) {
                                ProfileAvatar(
                                    avatarId = v.avatarUrl,
                                    fallbackName = v.displayName,
                                    size = 22
                                )
                            }
                        }
                    }

                    // Remaining indicator if more than 4 viewers
                    if (viewersForStep.size > 4) {
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text = "+${viewersForStep.size - 4}",
                            color = LavenderPrimary,
                            fontWeight = FontWeight.ExtraBold,
                            fontSize = 12.sp,
                            style = androidx.compose.ui.text.TextStyle(
                                shadow = Shadow(Color.Black.copy(alpha = 0.5f), Offset(1f, 1f), 2f)
                            )
                        )
                    }
                }

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    // Send message input field styled beautifully (smaller and beautiful, maxLines = 1, singleLine = true)
                    OutlinedTextField(
                        value = replyMessageInput,
                        onValueChange = { replyMessageInput = it },
                        placeholder = { Text("Send message...", color = Color.White.copy(alpha = 0.6f), fontSize = 12.sp, maxLines = 1) },
                        textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 12.sp),
                        singleLine = true,
                        maxLines = 1,
                        colors = TextFieldDefaults.colors(
                            focusedContainerColor = Color.White.copy(alpha = 0.15f),
                            unfocusedContainerColor = Color.White.copy(alpha = 0.15f),
                            focusedIndicatorColor = LavenderPrimary,
                            unfocusedIndicatorColor = Color.White.copy(alpha = 0.25f)
                        ),
                        modifier = Modifier
                            .weight(1f)
                            .height(48.dp),
                        shape = RoundedCornerShape(24.dp)
                    )

                    // Floating action send icon to submit comment reply references directly to active chats
                    IconButton(
                        onClick = {
                            if (replyMessageInput.isNotBlank()) {
                                val currentStep = steps.getOrNull(currentStepIndex)
                                val storyRefText = currentStep?.story?.contentText?.ifBlank { "Media Image/Video" } ?: "Aura Story"
                                viewModel.sendStoryReply(
                                    replyText = replyMessageInput,
                                    targetAuthorName = currentAuthorName,
                                    storyText = storyRefText
                                )
                                android.widget.Toast.makeText(context, "Story message sent directly to DM!", android.widget.Toast.LENGTH_SHORT).show()
                                replyMessageInput = ""
                            }
                        },
                        modifier = Modifier
                            .size(46.dp)
                            .background(LavenderPrimary, CircleShape)
                    ) {
                        Icon(Icons.AutoMirrored.Outlined.Send, "Send Reply to Chat", tint = Color.White, modifier = Modifier.size(18.dp))
                    }

                    // Swipeable quick reaction emojis list on the right side of Send Icon!
                    val quickEmojis = listOf("❤️", "😂", "😮", "😢", "🔥", "👍", "👏", "⚡", "✨", "💜", "🎉", "💯")
                    LazyRow(
                        modifier = Modifier
                            .weight(1.1f)
                            .height(48.dp),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        items(quickEmojis) { em ->
                            Card(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clickable {
                                        isPaused = true
                                        triggerBurstEmojis(em)
                                        // Realtime exact reaction recorded on click:
                                        val currentStep = steps.getOrNull(currentStepIndex)
                                        if (currentStep != null) {
                                            viewModel.reactToStory(currentStep.story.storyId, currentStepIndex, em)
                                        }
                                        storyViewerScope.launch {
                                            kotlinx.coroutines.delay(1200)
                                            isPaused = false
                                        }
                                    },
                                shape = CircleShape,
                                colors = CardDefaults.cardColors(containerColor = Color.White.copy(alpha = 0.2f)),
                                border = BorderStroke(0.5.dp, Color.White.copy(alpha = 0.3f))
                            ) {
                                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                                    Text(em, fontSize = 16.sp, textAlign = TextAlign.Center)
                                }
                            }
                        }
                    }
                }
            }
        }

        // Custom Overlay Floating Emojis floating animation block
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.BottomCenter) {
            floatingEmojis.forEach { fe ->
                val scaleFactor = (fe.yOffset + 400f) / 400f
                Text(
                    text = fe.emoji,
                    fontSize = (26 + (fe.id % 12).toInt()).sp,
                    modifier = Modifier
                        .offset(x = fe.xOffset.dp, y = fe.yOffset.dp)
                        .graphicsLayer(
                            scaleX = 0.5f + scaleFactor * 0.5f,
                            scaleY = 0.5f + scaleFactor * 0.5f,
                            alpha = scaleFactor
                        )
                )
            }
        }

        // --- REALTIME DYNAMIC STORY VIEWERS BOTTOM SHEET ---
        if (showViewersSheet) {
            // Dark elegant background backdrop
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(Color.Black.copy(alpha = 0.5f))
                    .clickable(
                        interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() },
                        indication = null
                    ) {
                        showViewersSheet = false
                        isPaused = false
                    }
                    .testTag("story_viewers_sheet_backdrop")
            )

            // Bottom drawer container sliding/overlay
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.BottomCenter
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .fillMaxHeight(0.55f) // occupies 55% of custom height
                        .background(Color.White, RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp))
                        .clickable(enabled = true, onClick = {}) // prevent click-through
                        .padding(top = 10.dp)
                        .testTag("story_viewers_bottom_sheet_content")
                ) {
                    // Safe spacing / Drag Bar handle
                    Box(
                        modifier = Modifier
                            .align(Alignment.CenterHorizontally)
                            .width(44.dp)
                            .height(4.dp)
                            .clip(CircleShape)
                            .background(Color(0xFFE4E6EB))
                    )

                    Spacer(modifier = Modifier.height(18.dp))

                    // Header Row
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 24.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(
                                imageVector = Icons.Default.Visibility,
                                contentDescription = "Eye Icon",
                                tint = LavenderPrimary,
                                modifier = Modifier.size(20.dp)
                            )
                            Spacer(modifier = Modifier.width(10.dp))
                            Text(
                                text = "Story Viewers (${viewersForStep.size})",
                                fontSize = 18.sp,
                                fontWeight = FontWeight.Bold,
                                color = Color.Black
                            )
                        }

                        // Close button circle
                        IconButton(
                            onClick = {
                                showViewersSheet = false
                                isPaused = false
                            },
                            modifier = Modifier
                                .size(32.dp)
                                .background(Color(0xFFF0F2F5), CircleShape)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close Sheet",
                                tint = Color.DarkGray,
                                modifier = Modifier.size(16.dp)
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(14.dp))
                    Divider(color = Color(0xFFF0F2F5), thickness = 1.dp)

                    if (viewersForStep.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .weight(1f),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                "No viewers yet for this story.",
                                color = Color.Gray,
                                fontSize = 14.sp
                            )
                        }
                    } else {
                        // Scrollable list of viewers
                        LazyColumn(
                            modifier = Modifier
                                .fillMaxWidth()
                                .weight(1f)
                                .padding(horizontal = 24.dp),
                            verticalArrangement = Arrangement.spacedBy(14.dp),
                            contentPadding = PaddingValues(vertical = 16.dp)
                        ) {
                            items(viewersForStep) { viewer ->
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("viewer_item_${viewer.userId}"),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        ProfileAvatar(
                                            avatarId = viewer.avatarUrl,
                                            fallbackName = viewer.displayName,
                                            size = 46
                                        )
                                        Spacer(modifier = Modifier.width(12.dp))
                                        Column {
                                            Text(
                                                text = viewer.displayName,
                                                fontWeight = FontWeight.Bold,
                                                color = Color.Black,
                                                fontSize = 15.sp
                                            )
                                            Spacer(modifier = Modifier.height(2.dp))
                                            Text(
                                                text = "Viewed story realtime",
                                                fontSize = 11.sp,
                                                color = Color.Gray
                                            )
                                        }
                                    }

                                    // Display reaction emoji given to that specific story step
                                    if (viewer.emoji.isNotBlank()) {
                                        Box(
                                            modifier = Modifier
                                                .size(36.dp)
                                                .background(Color(0xFFF5F6F9), CircleShape),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Text(
                                                text = viewer.emoji,
                                                fontSize = 18.sp,
                                                textAlign = TextAlign.Center
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

data class FloatingEmoji(
    val id: Long,
    val emoji: String,
    val xOffset: Float,
    val yOffset: Float
)

fun isVideoPath(path: String?): Boolean {
    if (path == null) return false
    val p = path.lowercase()
    return p.endsWith(".mp4") || p.endsWith(".mkv") || p.endsWith(".3gp") || p.endsWith(".mov") || p.contains("video")
}

@Composable
fun AuraVideoPlayer(
    videoPath: String,
    modifier: Modifier = Modifier,
    isMute: Boolean = false,
    isLooping: Boolean = true,
    isPaused: Boolean = false,
    seekTrigger: Int = 0,
    seekAmountMs: Int = 0,
    absoluteSeekMs: Int = -1,
    playbackSpeed: Float = 1.0f,
    onVideoDurationReady: ((Int) -> Unit)? = null,
    onProgressUpdate: ((currentMs: Int, durationMs: Int) -> Unit)? = null,
    onVideoEnded: (() -> Unit)? = null
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    var mediaPlayerRef by remember { mutableStateOf<android.media.MediaPlayer?>(null) }
    var videoViewRef by remember { mutableStateOf<android.widget.VideoView?>(null) }

    // Periodically update progress in real time
    LaunchedEffect(videoViewRef, isPaused, playbackSpeed) {
        if (videoViewRef != null) {
            while (true) {
                try {
                    val view = videoViewRef
                    if (view != null) {
                        val curr = view.currentPosition
                        val dur = view.duration
                        if (dur > 0) {
                            onProgressUpdate?.invoke(curr, dur)
                        }
                    }
                } catch (e: Exception) {}
                delay(250)
            }
        }
    }

    androidx.compose.ui.viewinterop.AndroidView(
        factory = { ctx ->
            android.widget.VideoView(ctx).apply {
                layoutParams = android.view.ViewGroup.LayoutParams(
                    android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                    android.view.ViewGroup.LayoutParams.MATCH_PARENT
                )
                videoViewRef = this
            }
        },
        modifier = modifier,
        update = { videoView ->
            val existingPath = videoView.tag as? String
            if (existingPath != videoPath) {
                videoView.tag = videoPath
                try {
                    val uri = if (videoPath.startsWith("/")) {
                        Uri.fromFile(java.io.File(videoPath))
                    } else {
                        Uri.parse(videoPath)
                    }
                    videoView.setVideoURI(uri)
                    videoView.setOnPreparedListener { mediaPlayer ->
                        mediaPlayerRef = mediaPlayer
                        mediaPlayer.isLooping = isLooping
                        if (isMute) {
                            mediaPlayer.setVolume(0f, 0f)
                        } else {
                            mediaPlayer.setVolume(1f, 1f)
                        }
                        
                        // Apply playback speed on prepare
                        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
                            try {
                                val params = mediaPlayer.playbackParams
                                params.speed = playbackSpeed
                                mediaPlayer.playbackParams = params
                            } catch (e: Exception) {}
                        }

                        val durationMs = mediaPlayer.duration
                        if (durationMs > 0) {
                            onVideoDurationReady?.invoke(durationMs)
                        }
                        if (isPaused) {
                            videoView.pause()
                        } else {
                            videoView.start()
                        }
                    }
                    videoView.setOnCompletionListener {
                        onVideoEnded?.invoke()
                    }
                    videoView.setOnErrorListener { _, _, _ ->
                        true
                    }
                } catch (e: Exception) {
                    android.util.Log.e("AuraVideoPlayer", "Error loading video: ${e.message}")
                }
            } else {
                mediaPlayerRef?.let { mp ->
                    try {
                        mp.isLooping = isLooping
                        if (isMute) {
                            mp.setVolume(0f, 0f)
                        } else {
                            mp.setVolume(1f, 1f)
                        }
                        
                        // Apply playback speed dynamically on update
                        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
                            try {
                                val params = mp.playbackParams
                                if (params.speed != playbackSpeed) {
                                    params.speed = playbackSpeed
                                    mp.playbackParams = params
                                }
                            } catch (e: Exception) {}
                        }
                    } catch (e: Exception) {
                        // ignore state exception
                    }
                }
                try {
                    if (isPaused) {
                        if (videoView.isPlaying) {
                            videoView.pause()
                        }
                    } else {
                        if (!videoView.isPlaying) {
                            videoView.start()
                        }
                    }
                } catch (e: Exception) {
                    // ignore
                }
            }
            
            // Handle seek request robustly using unique tag key
            val lastProcessedSeek = videoView.getTag(-9999) as? Int ?: 0
            if (seekTrigger != lastProcessedSeek) {
                videoView.setTag(-9999, seekTrigger)
                try {
                    if (absoluteSeekMs >= 0) {
                        videoView.seekTo(absoluteSeekMs.coerceIn(0, videoView.duration))
                    } else {
                        val currentPos = videoView.currentPosition
                        val targetPos = (currentPos + seekAmountMs).coerceIn(0, videoView.duration)
                        videoView.seekTo(targetPos)
                    }
                } catch (e: Exception) {}
            }
        },
        onRelease = { videoView ->
            videoView.stopPlayback()
        }
    )
}

@Composable
fun StoryCardItem(
    story: StoryEntity,
    viewModel: AuraViewModel
) {
    val firstPhotoUrl = remember(story.imageUrl) {
        story.imageUrl.split(",").firstOrNull { it.isNotBlank() }
    }

    val bgBrush = remember(story.gradientIndex) {
        if (story.gradientIndex in PremiumGradients.indices) {
            PremiumGradients[story.gradientIndex]
        } else {
            androidx.compose.ui.graphics.Brush.linearGradient(
                colors = listOf(Color(0xFF2E2A40), Color(0xFF1E1B29))
            )
        }
    }
    var feList by remember { mutableStateOf(emptyList<FloatingEmoji>()) }

    val reactionList = remember(story.reactions) {
        story.reactions.split(",").filter { it.isNotBlank() }
    }

    // Spawn loop for rising visual emojis inside card
    LaunchedEffect(reactionList) {
        if (reactionList.isNotEmpty()) {
            while (true) {
                kotlinx.coroutines.delay((1200..2500).random().toLong())
                val chosenEmoji = reactionList.random()
                val newEmoji = FloatingEmoji(
                    id = System.nanoTime(),
                    emoji = chosenEmoji,
                    xOffset = (-30..30).random().toFloat(),
                    yOffset = 100f
                )
                feList = feList + newEmoji
            }
        } else {
            feList = emptyList()
        }
    }

    // Animation loop (ticks cleanly)
    LaunchedEffect(feList) {
        if (feList.isNotEmpty()) {
            kotlinx.coroutines.delay(16)
            feList = feList.map {
                it.copy(yOffset = it.yOffset - 3f)
            }.filter { it.yOffset > -150f }
        }
    }

    Box(
        modifier = Modifier
            .width(100.dp)
            .aspectRatio(9f / 16f)
            .clip(RoundedCornerShape(14.dp))
            .background(if (firstPhotoUrl != null) Color.Transparent else Color.Black)
            .clickable { viewModel.showStory(story) }
    ) {
        // Full Image Background if available, otherwise Brush background
        if (firstPhotoUrl != null) {
            val isVideo = isVideoPath(firstPhotoUrl)
            if (isVideo) {
                AuraVideoPlayer(
                    videoPath = firstPhotoUrl,
                    modifier = Modifier.fillMaxSize(),
                    isMute = true
                )
            } else {
                AsyncImage(
                    model = firstPhotoUrl,
                    contentDescription = "Story image content",
                    contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                    modifier = Modifier.fillMaxSize()
                )
            }
            // Add subtle overlay to maintain avatar contrast ONLY for images, NOT for videos
            if (!isVideo) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(Color.Black.copy(alpha = 0.15f))
                )
            }
        } else {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(bgBrush)
            )
        }

        // Top avatar metadata
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(10.dp)
        ) {
            ProfileAvatar(
                avatarId = story.authorAvatar,
                size = 32,
                fallbackName = story.authorName,
                modifier = Modifier
                    .align(Alignment.TopStart)
                    .border(2.dp, LavenderPrimary, CircleShape)
            )

            // Bottom elements container
            Column(
                modifier = Modifier
                    .align(Alignment.BottomStart)
                    .fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(2.dp)
            ) {
                // Optional text overlay (ONLY show if NOT empty AND NOT the default sharing text)
                val cleanCap = story.contentText
                val isDefaultCap = cleanCap.contains("Sharing amazing Aura", ignoreCase = true) || cleanCap.isBlank()
                if (!isDefaultCap) {
                    Text(
                        text = cleanCap,
                        color = Color.White,
                        fontSize = 10.sp,
                        fontWeight = FontWeight.Normal,
                        maxLines = 2,
                        overflow = TextOverflow.Ellipsis,
                        style = LocalTextStyle.current.copy(
                            shadow = Shadow(Color.Black, Offset(1f, 1f), 3f)
                        )
                    )
                }

                // Author's Full Name (Clearly legible with drop shadow overlay)
                Text(
                    text = story.authorName,
                    color = Color.White,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.Bold,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis,
                    style = LocalTextStyle.current.copy(
                        shadow = Shadow(color = Color.Black.copy(alpha = 0.9f), offset = Offset(1f, 1f), blurRadius = 4f)
                    )
                )
            }
        }

        // Floating emojis overlapping frame (animating inside the card from bottom to top and vanishing)
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.BottomCenter
        ) {
            feList.forEach { fe ->
                val progress = (fe.yOffset + 150f) / 250f // 1.0f at bottom, 0.0f at top
                val scale = 0.6f + progress * 0.4f
                Text(
                    text = fe.emoji,
                    fontSize = 16.sp,
                    modifier = Modifier
                        .offset(x = fe.xOffset.dp, y = fe.yOffset.dp)
                        .graphicsLayer(
                            scaleX = scale,
                            scaleY = scale,
                            alpha = progress
                        )
                )
            }
        }
    }
}

// --- STORY CREATOR MODAL WITH ENHANCED FILE SELECTION, Horizontal side previews, CapCut Redirect AND AI TOGGLES ---
@Composable
fun StoryCreatorModal(
    state: AuraUiState,
    viewModel: AuraViewModel
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val allUsersList by viewModel.allUsers.collectAsStateWithLifecycle()
    
    var storyCaption by remember { mutableStateOf("") }
    var selectedGradientIdx by remember { mutableStateOf<Int?>(-1) } // Default color scheme starts with None (-1)
    var isAiRelatedStory by remember { mutableStateOf(false) }
    var websiteLinkStr by remember { mutableStateOf("") }

    // Multi-photo/video picker contract
    val multipleMediaLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.OpenMultipleDocuments()
    ) { uris ->
        if (uris != null && uris.isNotEmpty()) {
            val savedPaths = viewModel.copyMediaToPermanentStorage(uris)
            val hasVideo = uris.any { resolver ->
                context.contentResolver.getType(resolver)?.contains("video", ignoreCase = true) == true
            }
            if (state.storyCreatorMediaUris.isEmpty()) {
                viewModel.setStoryCreatorVisible(
                    visible = true,
                    mediaUris = savedPaths,
                    mediaType = if (hasVideo) "video" else "image"
                )
            } else {
                viewModel.addStoryCreatorMedia(
                    uris = savedPaths,
                    type = if (hasVideo) "video" else "image"
                )
            }
            android.widget.Toast.makeText(context, "${savedPaths.size} media files successfully loaded!", android.widget.Toast.LENGTH_SHORT).show()
        }
    }

    // Specific item replacement file launcher
    var replaceTargetIndex by remember { mutableStateOf(-1) }
    val replaceMediaLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.OpenDocument()
    ) { uri ->
        if (uri != null && replaceTargetIndex != -1) {
            val savedSingle = viewModel.copyMediaToPermanentStorage(listOf(uri)).firstOrNull()
            if (savedSingle != null) {
                viewModel.replaceStoryCreatorMediaAt(replaceTargetIndex, savedSingle)
                android.widget.Toast.makeText(context, "Item replaced successfully!", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }

    // Parse Mentions queries based on trailing characters
    val lastWord = storyCaption.split(" ", "\n").lastOrNull() ?: ""
    val isMentionQuerying = lastWord.startsWith("@") && lastWord.length >= 2
    val mentionTerm = if (isMentionQuerying) lastWord.substring(1).lowercase().trim() else ""
    val suggestedMentions = remember(allUsersList, mentionTerm, isMentionQuerying) {
        if (!isMentionQuerying) emptyList() else {
            allUsersList.filter { 
                it.displayName.lowercase().contains(mentionTerm) || 
                it.email.lowercase().contains(mentionTerm) 
            }
        }
    }

    androidx.compose.ui.window.Dialog(
        onDismissRequest = { viewModel.setStoryCreatorVisible(false) },
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier
                .fillMaxSize()
                .statusBarsPadding()
                .navigationBarsPadding()
                .imePadding(),
            color = Color.White,
            shape = RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp)
        ) {
            LazyColumn(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(16.dp),
                contentPadding = PaddingValues(bottom = 80.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // Header Title section
                item {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(
                                imageVector = Icons.Default.AutoAwesome,
                                contentDescription = null,
                                tint = LavenderPrimary,
                                modifier = Modifier.size(24.dp)
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = "Create Aura Story",
                                fontSize = 20.sp,
                                fontWeight = FontWeight.Bold,
                                color = LavenderPrimary
                            )
                        }
                        IconButton(onClick = { viewModel.setStoryCreatorVisible(false) }) {
                            Icon(Icons.Default.Close, "Dismiss Modal", tint = Color.DarkGray)
                        }
                    }
                }

                // Choose visual items box
                val mediaList = state.storyCreatorMediaUris
                if (mediaList.isEmpty()) {
                    item {
                        // Unselected state box (ONLY Choose photo/video text, as requested!)
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(150.dp)
                                .clickable {
                                    multipleMediaLauncher.launch(arrayOf("image/*", "video/*"))
                                },
                            colors = CardDefaults.cardColors(containerColor = LavenderPrimary.copy(alpha = 0.05f)),
                            shape = RoundedCornerShape(16.dp),
                            border = BorderStroke(1.5.dp, LavenderPrimary.copy(alpha = 0.25f))
                        ) {
                            Column(
                                modifier = Modifier.fillMaxSize(),
                                verticalArrangement = Arrangement.Center,
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Collections,
                                        contentDescription = "Pick Gallery",
                                        tint = LavenderPrimary,
                                        modifier = Modifier.size(36.dp)
                                    )
                                    Icon(
                                        imageVector = Icons.Default.VideoCall,
                                        contentDescription = "Pick Video",
                                        tint = LavenderPrimary,
                                        modifier = Modifier.size(36.dp)
                                    )
                                }
                                Spacer(modifier = Modifier.height(10.dp))
                                Text(
                                    text = "Choose Photo/Video", // Strictly left as requested!
                                    color = LavenderPrimary,
                                    fontWeight = FontWeight.ExtraBold,
                                    fontSize = 14.sp
                                )
                            }
                        }
                    }
                } else {
                    item {
                        // SELECTED MEDIA HORIZONTAL SIDE-BY-SIDE PREVIEWS INDEX PANEL
                        Column(
                            verticalArrangement = Arrangement.spacedBy(8.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Text(
                                text = "Selected Media Previews (${mediaList.size})",
                                fontWeight = FontWeight.Bold,
                                fontSize = 13.sp,
                                color = TextPrimary
                            )
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                itemsIndexed(mediaList) { idx, mPath ->
                                    val isFileVideo = isVideoPath(mPath)
                                    Box(
                                        modifier = Modifier
                                            .width(110.dp)
                                            .height(180.dp)
                                            .clip(RoundedCornerShape(14.dp))
                                            .background(Color.LightGray)
                                    ) {
                                        if (isFileVideo) {
                                            AuraVideoPlayer(
                                                videoPath = mPath,
                                                modifier = Modifier.fillMaxSize(),
                                                isMute = false
                                            )
                                        } else {
                                            AsyncImage(
                                                model = mPath,
                                                contentDescription = "Preview media item",
                                                contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                                modifier = Modifier.fillMaxSize()
                                            )
                                        }
                                        
                                        // Item actions float layout (Replace, Delete)
                                        Row(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .background(Color.Black.copy(alpha = 0.35f))
                                                .padding(horizontal = 4.dp, vertical = 2.dp)
                                                .align(Alignment.BottomCenter),
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            IconButton(
                                                onClick = {
                                                    replaceTargetIndex = idx
                                                    replaceMediaLauncher.launch(arrayOf("image/*", "video/*"))
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(Icons.Default.Cached, "Replace Item", tint = Color.White, modifier = Modifier.size(16.dp))
                                            }
                                            IconButton(
                                                onClick = {
                                                    viewModel.removeStoryCreatorMediaAt(idx)
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(Icons.Default.Delete, "Remove item", tint = Color.Red, modifier = Modifier.size(14.dp))
                                            }
                                        }
                                    }
                                }
                                
                                // Direct item appending plus card helper
                                item {
                                    Card(
                                        modifier = Modifier
                                            .width(110.dp)
                                            .height(180.dp)
                                            .clickable {
                                                multipleMediaLauncher.launch(arrayOf("image/*", "video/*"))
                                            },
                                        colors = CardDefaults.cardColors(containerColor = Color(0xFFF3F4F6)),
                                        shape = RoundedCornerShape(14.dp),
                                        border = BorderStroke(1.dp, Color.LightGray)
                                    ) {
                                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                                            Icon(Icons.Default.Add, "Append Media", tint = Color.DarkGray)
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Official CAPCUT Play Store Guide card block
                item {
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable {
                                try {
                                    val capcutPackage = "com.lemon.lv.international"
                                    val launchIntent = context.packageManager.getLaunchIntentForPackage(capcutPackage)
                                    if (launchIntent != null) {
                                        context.startActivity(launchIntent)
                                        android.widget.Toast.makeText(context, "Opening CapCut application directly! 🎥🎬", android.widget.Toast.LENGTH_SHORT).show()
                                    } else {
                                        // Try using URI scheme for CapCut
                                        try {
                                            val uriIntent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse("capcut://")).apply {
                                                addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                            }
                                            context.startActivity(uriIntent)
                                            android.widget.Toast.makeText(context, "Opening CapCut app via deep link! 🎬", android.widget.Toast.LENGTH_SHORT).show()
                                        } catch (e2: Exception) {
                                            val marketIntent = android.content.Intent(
                                                android.content.Intent.ACTION_VIEW,
                                                android.net.Uri.parse("market://details?id=$capcutPackage")
                                            ).apply {
                                                addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                            }
                                            context.startActivity(marketIntent)
                                            android.widget.Toast.makeText(context, "Redirecting to official play store CapCut app page...", android.widget.Toast.LENGTH_LONG).show()
                                        }
                                    }
                                } catch (e: Exception) {
                                    try {
                                        val webPlay = android.content.Intent(
                                            android.content.Intent.ACTION_VIEW,
                                            android.net.Uri.parse("https://play.google.com/store/apps/details?id=com.lemon.lv.international")
                                        )
                                        context.startActivity(webPlay)
                                    } catch (e3: Exception) {
                                        android.widget.Toast.makeText(context, "Cannot open Play Store or CapCut: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
                                    }
                                }
                            },
                        colors = CardDefaults.cardColors(containerColor = Color.Black),
                        shape = RoundedCornerShape(14.dp)
                    ) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(14.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(40.dp)
                                    .background(Color(0xFFE91E63), CircleShape),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(Icons.Default.MovieFilter, null, tint = Color.White, modifier = Modifier.size(20.dp))
                            }
                            Spacer(modifier = Modifier.width(12.dp))
                            Column(modifier = Modifier.weight(1f)) {
                                Text("Edit with CapCut App 🎬", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                                Text("Click to open CapCut in Google Play Store. Create templates & export instantly back into Aura!", color = Color.Gray, fontSize = 10.sp)
                            }
                            Icon(Icons.Default.ArrowForwardIos, null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                        }
                    }
                }

                // Input box fields layout section
                item {
                    Column(
                        modifier = Modifier.fillMaxWidth(),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            text = "Add Caption ✨",
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp,
                            color = Color.Black
                        )
                        OutlinedTextField(
                            value = storyCaption,
                            onValueChange = { storyCaption = it },
                            placeholder = { Text("What vibe is this story? Type @ to mention...", color = Color.DarkGray) },
                            textStyle = LocalTextStyle.current.copy(color = Color.Black), // PERFECT TEXT VISIBILITY FIX
                            colors = TextFieldDefaults.colors(
                                focusedContainerColor = Color.Transparent,
                                unfocusedContainerColor = Color.Transparent,
                                focusedTextColor = Color.Black,
                                unfocusedTextColor = Color.Black,
                                focusedIndicatorColor = LavenderPrimary,
                                unfocusedIndicatorColor = Color.LightGray
                            ),
                            modifier = Modifier.fillMaxWidth()
                        )

                        // Mention Suggestions List Row matches perfectly!
                        if (suggestedMentions.isNotEmpty()) {
                            LazyRow(
                                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                items(suggestedMentions) { usr ->
                                    Card(
                                        modifier = Modifier.clickable {
                                            val tokens = storyCaption.split(" ").toMutableList()
                                            if (tokens.isNotEmpty() && tokens.last().startsWith("@")) {
                                                tokens[tokens.size - 1] = "@${usr.displayName}"
                                            } else {
                                                tokens.add("@${usr.displayName}")
                                            }
                                            storyCaption = tokens.joinToString(" ") + " "
                                        },
                                        colors = CardDefaults.cardColors(containerColor = LavenderPrimary.copy(alpha = 0.12f)),
                                        shape = RoundedCornerShape(14.dp)
                                    ) {
                                        Row(
                                            modifier = Modifier.padding(horizontal = 10.dp, vertical = 6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            ProfileAvatar(avatarId = usr.avatarUrl ?: "avatar_default", size = 20)
                                            Spacer(modifier = Modifier.width(6.dp))
                                            Text("@${usr.displayName}", color = LavenderPrimary, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }
                            }
                        }

                        // Website Link Text box layout integration
                        Text(
                            text = "Add Website Link 🌐",
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp,
                            color = Color.Black
                        )
                        OutlinedTextField(
                            value = websiteLinkStr,
                            onValueChange = { websiteLinkStr = it },
                            placeholder = { Text("Add any website link here (e.g. example.com)", color = Color.DarkGray) },
                            textStyle = LocalTextStyle.current.copy(color = Color.Black),
                            colors = TextFieldDefaults.colors(
                                focusedContainerColor = Color.Transparent,
                                unfocusedContainerColor = Color.Transparent,
                                focusedTextColor = Color.Black,
                                unfocusedTextColor = Color.Black,
                                focusedIndicatorColor = LavenderPrimary,
                                unfocusedIndicatorColor = Color.LightGray
                            ),
                            modifier = Modifier.fillMaxWidth()
                        )

                        // AI Related toggle selection switch row
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(LavenderPrimary.copy(alpha = 0.05f), RoundedCornerShape(12.dp))
                                .border(0.5.dp, LavenderPrimary.copy(alpha = 0.15f), RoundedCornerShape(12.dp))
                                .padding(horizontal = 12.dp, vertical = 10.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(Icons.Default.AutoAwesome, "AI Toggle", tint = LavenderPrimary, modifier = Modifier.size(20.dp))
                                Spacer(modifier = Modifier.width(8.dp))
                                Column {
                                    Text("Mark as AI Related", color = TextPrimary, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                                    Text("Renders an AI tag inside story cards", color = Color.Gray, fontSize = 9.5.sp)
                                }
                            }
                            androidx.compose.material3.Switch(
                                checked = isAiRelatedStory,
                                onCheckedChange = { isAiRelatedStory = it },
                                colors = androidx.compose.material3.SwitchDefaults.colors(checkedThumbColor = LavenderPrimary)
                            )
                        }

                        // Theme selection: NONE gradient included as the first element!
                        Text(
                            text = "Story Card Theme Gradient 💜",
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp,
                            color = Color.Black
                        )
                        LazyRow(
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            // None Gradient Option card
                            item {
                                Box(
                                    modifier = Modifier
                                        .size(34.dp)
                                        .clip(CircleShape)
                                        .background(Color.White)
                                        .border(
                                            width = if (selectedGradientIdx == -1) 3.dp else 1.dp,
                                            color = if (selectedGradientIdx == -1) LavenderPrimary else Color.Gray,
                                            shape = CircleShape
                                        )
                                        .clickable { selectedGradientIdx = -1 },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .width(2.dp)
                                            .height(20.dp)
                                            .background(Color.Red)
                                    )
                                }
                            }

                            itemsIndexed(PremiumGradients) { idx, grad ->
                                Box(
                                    modifier = Modifier
                                        .size(34.dp)
                                        .clip(CircleShape)
                                        .background(grad)
                                        .border(
                                            width = if (selectedGradientIdx == idx) 3.dp else 0.dp,
                                            color = if (selectedGradientIdx == idx) Color.Black else Color.Transparent,
                                            shape = CircleShape
                                        )
                                        .clickable { selectedGradientIdx = idx }
                                )
                            }
                        }
                    }
                }

                // Submit Publish action button bar
                item {
                    Button(
                        onClick = {
                            val cap = storyCaption.ifBlank { "Sharing amazing Aura vibes! 💜⚡" }
                            val mediaURIs = state.storyCreatorMediaUris
                            viewModel.publishStoryWithMedia(
                                content = cap,
                                gradientIdx = selectedGradientIdx ?: -1,
                                mediaUrisList = mediaURIs,
                                isAiRelated = isAiRelatedStory,
                                websiteUrl = websiteLinkStr
                            )
                            android.widget.Toast.makeText(context, "Story published successfully! Disappears in 24 hours. 🕒✨", android.widget.Toast.LENGTH_LONG).show()
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = LavenderPrimary),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.fillMaxWidth().height(48.dp)
                    ) {
                        Text("Publish to Aura Story 🚀", fontWeight = FontWeight.Bold, fontSize = 15.sp, color = Color.White)
                    }
                }
            }
        }
    }
}

// --- COMMENTS SHEET DRAWER VIEW ---
@Composable
fun CommentsDrawer(
    state: AuraUiState,
    viewModel: AuraViewModel
) {
    val focusManager = LocalFocusManager.current
    val keyboardController = LocalSoftwareKeyboardController.current

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.Black.copy(alpha = 0.4f))
            .clickable { viewModel.closeComments() }
            .testTag("comments_overlay"),
        contentAlignment = Alignment.BottomCenter
    ) {
        // Comments box sheet
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .fillMaxHeight(0.7f)
                .clickable(enabled = false, onClick = {}) // prevent dismiss on card tap
                .shadow(20.dp, RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp)),
            colors = CardDefaults.cardColors(containerColor = Color.White),
            shape = RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp)
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .navigationBarsPadding()
            ) {
                // Comments header
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(viewModel.getTranslatedText("Dialogue comments"), color = TextPrimary, fontSize = 16.sp, fontWeight = FontWeight.Bold)
                    IconButton(onClick = { viewModel.closeComments() }) {
                        Icon(Icons.Default.Close, "Close comments", tint = LavenderPrimary)
                    }
                }
                Divider()

                // List of existing comments
                LazyColumn(
                    modifier = Modifier
                        .weight(1f)
                        .padding(horizontal = 16.dp),
                    contentPadding = PaddingValues(vertical = 12.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    if (state.activeComments.isEmpty()) {
                        item {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(32.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Icon(Icons.Default.ModeComment, null, tint = Color.LightGray, modifier = Modifier.size(48.dp))
                                Spacer(modifier = Modifier.height(8.dp))
                                Text(viewModel.getTranslatedText("No comments yet. Write the first response!"), color = Color.Gray)
                            }
                        }
                    }

                    items(state.activeComments) { comment ->
                        Row(
                            verticalAlignment = Alignment.Top,
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            ProfileAvatar(avatarId = comment.authorAvatar, size = 32, fallbackName = comment.authorName)
                            Spacer(modifier = Modifier.width(10.dp))
                            Column(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(SurfaceLight)
                                    .padding(10.dp)
                                    .weight(1f)
                            ) {
                                Text(comment.authorName, color = TextPrimary, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(viewModel.getTranslatedText(comment.text), color = TextPrimary, fontSize = 13.sp)
                            }
                        }
                    }
                }

                Divider()

                // Insert Comments Bar panel
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    OutlinedTextField(
                        value = state.commentInputText,
                        onValueChange = { viewModel.setCommentInput(it) },
                        placeholder = { Text(viewModel.getTranslatedText("Write a supportive aura comment...")) },
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
                        keyboardActions = KeyboardActions(onSend = {
                            viewModel.submitComment()
                            focusManager.clearFocus()
                            keyboardController?.hide()
                        }),
                        modifier = Modifier
                            .weight(1f)
                            .testTag("comment_field_input"),
                        shape = RoundedCornerShape(20.dp)
                    )

                    Spacer(modifier = Modifier.width(10.dp))

                    IconButton(
                        onClick = {
                            viewModel.submitComment()
                            focusManager.clearFocus()
                            keyboardController?.hide()
                        },
                        colors = IconButtonDefaults.iconButtonColors(contentColor = LavenderPrimary)
                    ) {
                        Icon(Icons.AutoMirrored.Outlined.Send, "Send comment")
                    }
                }
            }
        }
    }
}

// --- SCREEN 5: REAL CHAT ROOM VIEW PANEL ---
@Composable
fun ChatRoomScreen(
    state: AuraUiState,
    viewModel: AuraViewModel,
    otherUser: UserEntity
) {
    BackHandler(enabled = true) {
        viewModel.goBack()
    }

    val messagesList by viewModel.getActiveMessages().collectAsStateWithLifecycle(initialValue = emptyList())
    var textInput by remember { mutableStateOf("") }
    val focusManager = LocalFocusManager.current
    val keyboardController = LocalSoftwareKeyboardController.current

    Scaffold(
        topBar = {
            TopAppBar(
                title = {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        ProfileAvatar(avatarId = otherUser.avatarUrl, size = 32, showOnlineStatus = true, fallbackName = otherUser.displayName)
                        Spacer(modifier = Modifier.width(10.dp))
                        Column {
                            Text(otherUser.displayName, color = TextPrimary, fontSize = 15.sp, fontWeight = FontWeight.Bold)
                            Text("Active Status Online", color = OnlineGreen, fontSize = 10.sp)
                        }
                    }
                },
                navigationIcon = {
                    IconButton(onClick = { viewModel.navigateTo(Screen.Main) }) {
                        Icon(Icons.Default.ArrowBack, "Back", tint = LavenderPrimary)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = Color.White)
            )
        },
        containerColor = BackgroundWhite,
        modifier = Modifier.testTag("chat_room_screen")
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .navigationBarsPadding()
        ) {
            // Chat streams list
            LazyColumn(
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 16.dp),
                contentPadding = PaddingValues(vertical = 12.dp),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                items(messagesList) { msg ->
                    val isOwn = msg.senderName != otherUser.displayName
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = if (isOwn) Arrangement.End else Arrangement.Start
                    ) {
                        if (!isOwn) {
                            ProfileAvatar(avatarId = msg.senderAvatar, size = 28, fallbackName = msg.senderName)
                            Spacer(modifier = Modifier.width(8.dp))
                        }

                        Box(
                            modifier = Modifier
                                .clip(
                                    RoundedCornerShape(
                                        topStart = 16.dp,
                                        topEnd = 16.dp,
                                        bottomStart = if (isOwn) 16.dp else 4.dp,
                                        bottomEnd = if (isOwn) 4.dp else 16.dp
                                    )
                                )
                                .background(if (isOwn) LavenderPrimary else Color(0xFFF1EFF9))
                                .padding(12.dp)
                                .widthIn(max = 240.dp)
                        ) {
                            Text(
                                text = msg.content,
                                color = if (isOwn) Color.White else TextPrimary,
                                fontSize = 13.sp
                            )
                        }
                    }
                }
            }

            Divider()

            // Text input bar
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(12.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = textInput,
                    onValueChange = { textInput = it },
                    placeholder = { Text("Dialogue message with ${otherUser.displayName}...") },
                    singleLine = true,
                    keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
                    keyboardActions = KeyboardActions(onSend = {
                        if (textInput.isNotBlank()) {
                            viewModel.sendChatMessage(textInput)
                            textInput = ""
                        }
                        focusManager.clearFocus()
                        keyboardController?.hide()
                    }),
                    modifier = Modifier
                        .weight(1f)
                        .testTag("chat_input_field"),
                    shape = RoundedCornerShape(20.dp)
                )

                Spacer(modifier = Modifier.width(10.dp))

                IconButton(
                    onClick = {
                        if (textInput.isNotBlank()) {
                            viewModel.sendChatMessage(textInput)
                            textInput = ""
                        }
                        focusManager.clearFocus()
                        keyboardController?.hide()
                    },
                    colors = IconButtonDefaults.iconButtonColors(contentColor = LavenderPrimary)
                ) {
                    Icon(Icons.AutoMirrored.Outlined.Send, "Send MESSAGE")
                }
            }
        }
    }
}

