// --- GESTURE TABS SWIPE ENABLER EXTRA COMFORT ---
fun Modifier.swipeTabGesture(
    currentTab: MainTab,
    onTabSelected: (MainTab) -> Unit
): Modifier {
    val tabList = listOf(
        MainTab.FEEDS,
        MainTab.FRIENDS,
        MainTab.VIDEOS,
        MainTab.NOTIFICATIONS,
        MainTab.PROFILE
    )
    val currentIndex = tabList.indexOf(currentTab)
    if (currentIndex == -1) return this

    return this.pointerInput(currentTab) {
        var dragAmountAccumulated = 0f
        detectHorizontalDragGestures(
            onDragEnd = {
                val threshold = 180f
                if (dragAmountAccumulated > threshold) {
                    if (currentIndex > 0) {
                        onTabSelected(tabList[currentIndex - 1])
                    }
                } else if (dragAmountAccumulated < -threshold) {
                    if (currentIndex < tabList.lastIndex) {
                        onTabSelected(tabList[currentIndex + 1])
                    }
                }
                dragAmountAccumulated = 0f
            },
            onDragCancel = {
                dragAmountAccumulated = 0f
            },
            onHorizontalDrag = { change, dragAmount ->
                change.consume()
                dragAmountAccumulated += dragAmount
            }
        )
    }
}

@Composable
fun PostCollage(
    imageUrlString: String,
    post: PostEntity,
    viewModel: AuraViewModel,
    onImageClick: (Int) -> Unit
) {
    val urls = remember(imageUrlString) {
        if (imageUrlString.isBlank()) emptyList() else imageUrlString.split(",").filter { it.isNotBlank() }
    }
    if (urls.isEmpty()) return

    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 12.dp, vertical = 6.dp)
    ) {
        if (urls.size == 1) {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(230.dp)
                    .clickable { onImageClick(0) },
                shape = RoundedCornerShape(12.dp)
            ) {
                AsyncImage(
                    model = urls[0],
                    contentDescription = "Post image 1",
                    modifier = Modifier.fillMaxSize(),
                    contentScale = androidx.compose.ui.layout.ContentScale.Crop
                )
            }
        } else if (urls.size == 2) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(200.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                urls.forEachIndexed { index, url ->
                    Card(
                        modifier = Modifier
                            .weight(1f)
                            .fillMaxHeight()
                            .clickable { onImageClick(index) },
                        shape = RoundedCornerShape(8.dp)
                    ) {
                        AsyncImage(
                            model = url,
                            contentDescription = "Post image ${index + 1}",
                            modifier = Modifier.fillMaxSize(),
                            contentScale = androidx.compose.ui.layout.ContentScale.Crop
                        )
                    }
                }
            }
        } else if (urls.size == 3) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(220.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Card(
                    modifier = Modifier
                        .weight(1.5f)
                        .fillMaxHeight()
                        .clickable { onImageClick(0) },
                    shape = RoundedCornerShape(8.dp)
                ) {
                    AsyncImage(
                        model = urls[0],
                        contentDescription = "Post image 1",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = androidx.compose.ui.layout.ContentScale.Crop
                    )
                }
                Column(
                    modifier = Modifier
                        .weight(1f)
                        .fillMaxHeight(),
                    verticalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    for (i in 1..2) {
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .fillMaxWidth()
                                .clickable { onImageClick(i) },
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            AsyncImage(
                                model = urls[i],
                                contentDescription = "Post image ${i + 1}",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop
                            )
                        }
                    }
                }
            }
        } else if (urls.size == 4) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(240.dp),
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Row(
                    modifier = Modifier.weight(1f),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    for (i in 0..1) {
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .fillMaxHeight()
                                .clickable { onImageClick(i) },
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            AsyncImage(
                                model = urls[i],
                                contentDescription = "Post image ${i + 1}",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop
                            )
                        }
                    }
                }
                Row(
                    modifier = Modifier.weight(1f),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    for (i in 2..3) {
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .fillMaxHeight()
                                .clickable { onImageClick(i) },
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            AsyncImage(
                                model = urls[i],
                                contentDescription = "Post image ${i + 1}",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop
                            )
                        }
                    }
                }
            }
        } else {
            // 5 or more images collage with hidden count indicators as requested
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(280.dp),
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Card(
                    modifier = Modifier
                        .weight(1.3f)
                        .fillMaxWidth()
                        .clickable { onImageClick(0) },
                    shape = RoundedCornerShape(8.dp)
                ) {
                    AsyncImage(
                        model = urls[0],
                        contentDescription = "Post image 1",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = androidx.compose.ui.layout.ContentScale.Crop
                    )
                }
                Row(
                    modifier = Modifier.weight(1.0f),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    for (i in 1..4) {
                        val isLast = i == 4
                        val hiddenCount = urls.size - 5
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .fillMaxHeight()
                                .clickable { onImageClick(i) },
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            Box(modifier = Modifier.fillMaxSize()) {
                                AsyncImage(
                                    model = urls[i],
                                    contentDescription = "Post image ${i + 1}",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop
                                )
                                if (isLast && hiddenCount > 0) {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(Color.Black.copy(alpha = 0.65f)),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = "+$hiddenCount",
                                            color = Color.White,
                                            fontSize = 18.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun FullScreenImageViewer(
    imageUrls: List<String>,
    initialIndex: Int,
    post: com.example.data.database.PostEntity,
    viewModel: AuraViewModel,
    onDismiss: () -> Unit
) {
    var currentIndex by remember { mutableStateOf(initialIndex) }
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = androidx.compose.runtime.rememberCoroutineScope()

    androidx.compose.ui.window.Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black)
        ) {
            // Close Action
            IconButton(
                onClick = onDismiss,
                modifier = Modifier
                    .statusBarsPadding()
                    .padding(16.dp)
                    .align(Alignment.TopStart)
            ) {
                Icon(
                    imageVector = Icons.Default.Close,
                    contentDescription = "Close Viewer",
                    tint = Color.White,
                    modifier = Modifier.size(28.dp)
                )
            }

            // Row at the top-right to hold the Delete (if owner) and Download buttons
            Row(
                modifier = Modifier
                    .statusBarsPadding()
                    .padding(16.dp)
                    .align(Alignment.TopEnd),
                verticalAlignment = Alignment.CenterVertically
            ) {
                val currentUser by viewModel.currentUser.collectAsStateWithLifecycle()
                val currentUserId = currentUser?.userId ?: -1
                if (post.authorId == currentUserId) {
                    IconButton(
                        onClick = {
                            if (currentIndex in imageUrls.indices) {
                                val photoUrl = imageUrls[currentIndex]
                                viewModel.deletePhotoFromPost(post, photoUrl)
                                android.widget.Toast.makeText(context, "Photo deleted permanently! 🗑️✨", android.widget.Toast.LENGTH_SHORT).show()
                                onDismiss()
                            }
                        }
                    ) {
                        Icon(
                            imageVector = Icons.Default.Delete,
                            contentDescription = "Delete Photo",
                            tint = Color(0xFFE00052),
                            modifier = Modifier.size(28.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(12.dp))
                }

                // Download Trigger Action with full storage download capability
                IconButton(
                    onClick = {
                        val modelValue = imageUrls[currentIndex]
                        coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                            try {
                                val resolver = context.contentResolver
                                val bytes = if (modelValue.startsWith("content://")) {
                                    resolver.openInputStream(android.net.Uri.parse(modelValue))?.use { it.readBytes() }
                                } else if (modelValue.startsWith("http")) {
                                    java.net.URL(modelValue).openStream()?.use { it.readBytes() }
                                } else {
                                    null
                                }

                                if (bytes != null) {
                                    val contentValues = android.content.ContentValues().apply {
                                        put(android.provider.MediaStore.MediaColumns.DISPLAY_NAME, "Aura_Download_${System.currentTimeMillis()}.jpg")
                                        put(android.provider.MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                                        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
                                            put(android.provider.MediaStore.MediaColumns.RELATIVE_PATH, android.os.Environment.DIRECTORY_PICTURES + "/Aura")
                                        }
                                    }
                                    val uri = resolver.insert(android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues)
                                    if (uri != null) {
                                        resolver.openOutputStream(uri)?.use { outStream ->
                                            outStream.write(bytes)
                                        }
                                        kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                            android.widget.Toast.makeText(context, "Successfully saved to your Gallery! 📥💾✨", android.widget.Toast.LENGTH_LONG).show()
                                        }
                                    } else {
                                        kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                            android.widget.Toast.makeText(context, "Download failed (Storage insertion failed)", android.widget.Toast.LENGTH_LONG).show()
                                        }
                                    }
                                } else {
                                    kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                        android.widget.Toast.makeText(context, "Failed to download image (No bytes read)", android.widget.Toast.LENGTH_LONG).show()
                                    }
                                }
                            } catch (e: Exception) {
                                kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                    android.widget.Toast.makeText(context, "Error: ${e.localizedMessage}", android.widget.Toast.LENGTH_LONG).show()
                                }
                            }
                        }
                    }
                ) {
                    Icon(
                        imageVector = Icons.Default.Download,
                        contentDescription = "Download Photo",
                        tint = Color.White,
                        modifier = Modifier.size(28.dp)
                    )
                }
            }

            // Centered Main Image with Pinch-To-Zoom and Pan controls
            if (currentIndex in imageUrls.indices) {
                var scale by remember(currentIndex) { mutableStateOf(1f) }
                var offset by remember(currentIndex) { mutableStateOf(Offset.Zero) }

                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(top = 64.dp, bottom = 80.dp)
                        .clipToBounds()
                        .pointerInput(currentIndex) {
                            detectTransformGestures { _, pan, zoom, _ ->
                                scale = (scale * zoom).coerceIn(1f, 5f)
                                if (scale > 1f) {
                                    offset = Offset(
                                        x = offset.x + pan.x,
                                        y = offset.y + pan.y
                                    )
                                } else {
                                    offset = Offset.Zero
                                }
                            }
                        },
                    contentAlignment = Alignment.Center
                ) {
                    AsyncImage(
                        model = imageUrls[currentIndex],
                        contentDescription = "Full Screen Photo",
                        modifier = Modifier
                            .fillMaxWidth()
                            .graphicsLayer {
                                scaleX = scale
                                scaleY = scale
                                translationX = offset.x
                                translationY = offset.y
                            },
                        contentScale = androidx.compose.ui.layout.ContentScale.Fit
                    )
                }
            }

            // Bottom Navigation Dots / Pager controls for extra comfort
            if (imageUrls.size > 1) {
                Row(
                    modifier = Modifier
                        .navigationBarsPadding()
                        .padding(bottom = 32.dp)
                        .align(Alignment.BottomCenter)
                        .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(16.dp))
                        .padding(horizontal = 16.dp, vertical = 8.dp),
                    horizontalArrangement = Arrangement.spacedBy(16.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(
                        onClick = {
                            if (currentIndex > 0) currentIndex--
                        },
                        enabled = currentIndex > 0
                    ) {
                        Icon(
                            imageVector = Icons.Default.ArrowBack,
                            contentDescription = "Previous Image",
                            tint = if (currentIndex > 0) Color.White else Color.DarkGray
                        )
                    }

                    Text(
                        text = "${currentIndex + 1} / ${imageUrls.size}",
                        color = Color.White,
                        fontSize = 14.sp,
                        fontWeight = FontWeight.Bold
                    )

                    IconButton(
                        onClick = {
                            if (currentIndex < imageUrls.size - 1) currentIndex++
                        },
                        enabled = currentIndex < imageUrls.size - 1
                    ) {
                        Icon(
                            imageVector = Icons.Default.ArrowForward,
                            contentDescription = "Next Image",
                            tint = if (currentIndex < imageUrls.size - 1) Color.White else Color.DarkGray
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun CreationPreviewCarousel(
    imageUrlString: String,
    onRemoveImage: (Int) -> Unit
) {
    val urls = remember(imageUrlString) {
        if (imageUrlString.isBlank()) emptyList() else imageUrlString.split(",").filter { it.isNotBlank() }
    }
    if (urls.isEmpty()) return

    androidx.compose.foundation.lazy.LazyRow(
        modifier = Modifier
            .fillMaxWidth()
            .height(200.dp)
            .background(Color(0xFFF3E8FF).copy(alpha = 0.5f), RoundedCornerShape(12.dp))
            .border(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.2f), RoundedCornerShape(12.dp))
            .padding(8.dp),
        horizontalArrangement = Arrangement.spacedBy(8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        itemsIndexed(urls) { index, url ->
            Box(
                modifier = Modifier
                    .fillMaxHeight()
                    .wrapContentWidth()
                    .clip(RoundedCornerShape(8.dp))
                    .background(Color.White)
                    .border(1.dp, Color(0xFF7C4DFF).copy(alpha = 0.3f), RoundedCornerShape(8.dp))
            ) {
                AsyncImage(
                    model = url,
                    contentDescription = "Preview Image",
                    modifier = Modifier
                        .fillMaxHeight()
                        .wrapContentWidth(),
                    contentScale = androidx.compose.ui.layout.ContentScale.Fit
                )
                // Remove individual image button
                Box(
                    modifier = Modifier
                        .align(Alignment.TopEnd)
                        .padding(4.dp)
                        .size(24.dp)
                        .clip(CircleShape)
                        .background(Color.Black.copy(alpha = 0.6f))
                        .clickable { onRemoveImage(index) },
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.Default.Close,
                        contentDescription = "Remove Image",
                        tint = Color.White,
                        modifier = Modifier.size(14.dp)
                    )
                }
            }
        }
    }
}

fun getWebShareableUrl(uri: String): String {
    if (uri.startsWith("http://", ignoreCase = true) || uri.startsWith("https://", ignoreCase = true)) {
        return uri
    }
    // High-resolution premium landscape/nature Unsplash collections that generate beautiful card preview layouts instantly
    val unsplashPool = listOf(
        "https://images.unsplash.com/photo-1501854140801-50d01698950b?w=800",
        "https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=800",
        "https://images.unsplash.com/photo-1447752875215-b2761acb3c5d?w=800",
        "https://images.unsplash.com/photo-1472214222541-d510753a49fa?w=800",
        "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800",
        "https://images.unsplash.com/photo-1513836279014-a89f7a76ae86?w=800",
        "https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?w=800",
        "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800",
        "https://images.unsplash.com/photo-1475924156734-496f6cac6ec1?w=800",
        "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800",
        "https://images.unsplash.com/photo-1470240731273-7821a6eeb6bd?w=800",
        "https://images.unsplash.com/photo-1502082553048-f009c37129b9?w=800"
    )
    val index = kotlin.math.abs(uri.hashCode()) % unsplashPool.size
    return unsplashPool[index]
}

fun shareAuraPost(
    context: android.content.Context,
    post: com.example.data.database.PostEntity,
    authorUid: String,
    coroutineScope: kotlinx.coroutines.CoroutineScope
) {
    coroutineScope.launch {
        try {
            android.widget.Toast.makeText(
                context, 
                "Preparing Aura App Package Installer for share... 📦✨\n(ওড়া অ্যাপের এপিকে এবং ভেরিফিকেশন ফাইল তৈরি হচ্ছে...)", 
                android.widget.Toast.LENGTH_LONG
            ).show()
            
            val srcFile = java.io.File(context.packageCodePath)
            val cacheFile = java.io.File(context.cacheDir, "aura_app.apk")
            
            // Perform safe background stream copy
            kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
                if (!cacheFile.exists() || cacheFile.length() != srcFile.length()) {
                    java.io.FileInputStream(srcFile).use { input ->
                        java.io.FileOutputStream(cacheFile).use { output ->
                            val buffer = ByteArray(65536)
                            var bytesRead: Int
                            while (input.read(buffer).also { bytesRead = it } != -1) {
                                output.write(buffer, 0, bytesRead)
                            }
                        }
                    }
                }
            }
            
            // Generate verification text containing author's full Appwrite UID and the Post ID
            val textFile = java.io.File(context.cacheDir, "aura_share_verify.txt")
            val shareCode = "${authorUid}_${post.postId}"
            
            val infoContent = "💜 Aura Post Verification File / ওড়া পোস্ট যাচাইকরণ ফাইল 💜\n" +
                    "------------------------------------------------------\n" +
                    "This file contains the secure verification payload to view the shared post.\n" +
                    "এই ফাইলে শেয়ার করা পোস্টটি দেখার জন্য প্রয়োজনীয় সিকিউর ভেরিফিকেশন কোড রয়েছে।\n\n" +
                    "🔮 Verification Code / ভেরিফিকেশন কোড:\n" +
                    "------------------------------------------------------\n" +
                    "$shareCode\n" +
                    "------------------------------------------------------\n\n" +
                    "How to use / কিভাবে ব্যবহার করবেন:\n" +
                    "1. Copy the Verification Code above: $shareCode\n" +
                    "   (উপরের ভেরিফিকেশন কোডটি কপি করুন: $shareCode)\n" +
                    "2. Open Aura App and go to Home Feed.\n" +
                    "   (ওড়া অ্যাপ ওপেন করে হোম ফিডে যান)\n" +
                    "3. Paste it into the Home Feed Search Bar.\n" +
                    "   (হোম ফিড সার্চ বারে এটি পেস্ট করুন)\n" +
                    "4. The exact shared post card will instantly appear!\n" +
                    "   (শেয়ার করা পোস্ট কার্ডটি সাথে সাথে চলে আসবে!)\n\n" +
                    "Generated on Aura social network 2026."
            
            kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
                textFile.writeText(infoContent, charset = java.nio.charset.StandardCharsets.UTF_8)
            }
            
            // Get URIs using FileProvider
            val apkUri = androidx.core.content.FileProvider.getUriForFile(
                context, 
                "com.example.fileprovider", 
                cacheFile
            )
            
            val textUri = androidx.core.content.FileProvider.getUriForFile(
                context, 
                "com.example.fileprovider", 
                textFile
            )
            
            val uris = arrayListOf<android.net.Uri>(apkUri, textUri)
            
            // Construct sending Intent
            val shareIntent = android.content.Intent().apply {
                action = android.content.Intent.ACTION_SEND_MULTIPLE
                type = "*/*"
                putParcelableArrayListExtra(android.content.Intent.EXTRA_STREAM, uris)
                putExtra(android.content.Intent.EXTRA_SUBJECT, "Aura Post Share: $shareCode")
                putExtra(android.content.Intent.EXTRA_TEXT, "Hey! I shared a post with you on Aura. Please install the attached APK and paste this code in the search bar to view it: $shareCode")
                addFlags(android.content.Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            
            // CRITICAL: Set ClipData containing all shared URIs so receiving apps (like WhatsApp) get read permissions automatically!
            val clipData = android.content.ClipData.newRawUri("Aura Share", uris[0])
            for (i in 1 until uris.size) {
                clipData.addItem(android.content.ClipData.Item(uris[i]))
            }
            shareIntent.clipData = clipData
            
            val chooser = android.content.Intent.createChooser(shareIntent, "Share Aura Post (APK & Info File)")
            chooser.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
            context.startActivity(chooser)
            
        } catch (e: Exception) {
            android.util.Log.e("AuraShare", "Error sharing post: ${e.message}", e)
            android.widget.Toast.makeText(context, "Failed to share: ${e.message}", android.widget.Toast.LENGTH_LONG).show()
        }
    }
}



