@Composable
fun InteractiveMediaViewerDialog(
    mediaUrl: String?,
    fallbackName: String?,
    onDismiss: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    
    androidx.compose.ui.window.Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false,
            dismissOnBackPress = true,
            dismissOnClickOutside = true
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black)
        ) {
            // Close Button
            IconButton(
                onClick = onDismiss,
                modifier = Modifier
                    .statusBarsPadding()
                    .padding(16.dp)
                    .align(Alignment.TopStart)
                    .background(Color.Black.copy(alpha = 0.5f), CircleShape)
            ) {
                Icon(
                    imageVector = Icons.Default.Close,
                    contentDescription = "Close Viewer",
                    tint = Color.White
                )
            }

            // Download Button (Only if there is a real Uri)
            val hasRealUri = !mediaUrl.isNullOrBlank() && (mediaUrl.startsWith("content://") || mediaUrl.startsWith("http") || mediaUrl.contains("/"))
            if (hasRealUri) {
                IconButton(
                    onClick = {
                        coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                            try {
                                val resolver = context.contentResolver
                                val bytes = resolver.openInputStream(android.net.Uri.parse(mediaUrl))?.use { it.readBytes() }
                                if (bytes != null && bytes.isNotEmpty()) {
                                    val contentValues = android.content.ContentValues().apply {
                                        put(android.provider.MediaStore.MediaColumns.DISPLAY_NAME, "Aura_Media_${System.currentTimeMillis()}.jpg")
                                        put(android.provider.MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                                        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
                                            put(android.provider.MediaStore.MediaColumns.RELATIVE_PATH, android.os.Environment.DIRECTORY_PICTURES + "/Aura")
                                        }
                                    }
                                    val uri = resolver.insert(android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues)
                                    if (uri != null) {
                                        resolver.openOutputStream(uri)?.use { outStream ->
                                            outStream.write(bytes)
                                        }
                                        kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                            android.widget.Toast.makeText(context, "Saved image to Gallery! 📥💖", android.widget.Toast.LENGTH_LONG).show()
                                        }
                                    } else {
                                        kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                            android.widget.Toast.makeText(context, "Insertion failed", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    }
                                } else {
                                    // remote URL toast
                                    kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                        android.widget.Toast.makeText(context, "Remote image download started... (copied url to Clipboard)", android.widget.Toast.LENGTH_LONG).show()
                                        val clipboardManager = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                        clipboardManager.setPrimaryClip(android.content.ClipData.newPlainText("Aura Media Url", mediaUrl))
                                    }
                                }
                            } catch (e: Exception) {
                                kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                    android.widget.Toast.makeText(context, "Download tip: Remote URL reference saved to system clipboard.", android.widget.Toast.LENGTH_LONG).show()
                                    val clipboardManager = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                    clipboardManager.setPrimaryClip(android.content.ClipData.newPlainText("Aura Media Url", mediaUrl))
                                }
                            }
                        }
                    },
                    modifier = Modifier
                        .statusBarsPadding()
                        .padding(16.dp)
                        .align(Alignment.TopEnd)
                        .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                ) {
                    Icon(
                        imageVector = Icons.Default.Download,
                        contentDescription = "Download Media",
                        tint = Color.White
                    )
                }
            }

            // Pinch and zoom interaction area
            var scale by remember { mutableStateOf(1f) }
            var offset by remember { mutableStateOf(Offset.Zero) }

            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(top = 80.dp, bottom = 120.dp)
                    .clipToBounds()
                    .pointerInput(Unit) {
                        detectTransformGestures { _, pan, zoom, _ ->
                            scale = (scale * zoom).coerceIn(1f, 5f)
                            if (scale > 1f) {
                                offset = Offset(
                                    x = offset.x + pan.x,
                                    y = offset.y + pan.y
                                )
                            } else {
                                offset = Offset.Zero
                            }
                        }
                    },
                contentAlignment = Alignment.Center
            ) {
                if (hasRealUri) {
                    AsyncImage(
                        model = mediaUrl,
                        contentDescription = "Interactive Photo",
                        modifier = Modifier
                            .fillMaxWidth()
                            .graphicsLayer {
                                scaleX = scale
                                scaleY = scale
                                translationX = offset.x
                                translationY = offset.y
                            },
                        contentScale = androidx.compose.ui.layout.ContentScale.Fit
                    )
                } else {
                    // Fallback to high resolution ProfileAvatar
                    Box(
                        modifier = Modifier
                            .size(240.dp)
                            .shadow(8.dp, CircleShape)
                            .background(Color.White, CircleShape)
                            .graphicsLayer {
                                scaleX = scale
                                scaleY = scale
                                translationX = offset.x
                                translationY = offset.y
                            },
                        contentAlignment = Alignment.Center
                    ) {
                        ProfileAvatar(
                            avatarId = mediaUrl ?: "avatar_user_main",
                            modifier = Modifier.fillMaxSize(),
                            size = 240,
                            fallbackName = fallbackName,
                            showOnlineStatus = false
                        )
                    }
                }
            }

            // Reaction Emojis Toolbar at Bottom
            Row(
                modifier = Modifier
                    .navigationBarsPadding()
                    .padding(bottom = 32.dp)
                    .align(Alignment.BottomCenter)
                    .background(Color.White.copy(alpha = 0.15f), RoundedCornerShape(24.dp))
                    .padding(horizontal = 16.dp, vertical = 8.dp),
                horizontalArrangement = Arrangement.spacedBy(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                listOf("❤️", "🔥", "😮", "⚡", "💜").forEach { emoji ->
                    Box(
                        modifier = Modifier
                            .size(40.dp)
                            .clip(CircleShape)
                            .background(Color.Black.copy(alpha = 0.4f))
                            .clickable {
                                android.widget.Toast.makeText(context, "Smashed reaction $emoji ! ✨💜", android.widget.Toast.LENGTH_SHORT).show()
                            },
                        contentAlignment = Alignment.Center
                    ) {
                        Text(text = emoji, fontSize = 20.sp)
                    }
                }
            }
        }
    }
}

// --- Video & Reel Thumbnail Helper ---
@Composable
fun getThumbnailUrl(videoUrl: String, thumbnailUrl: String): String {
    val ytId = com.example.data.network.extractYouTubeVideoId(videoUrl)
    return if (!ytId.isNullOrBlank()) {
        "https://img.youtube.com/vi/$ytId/hqdefault.jpg"
    } else if (thumbnailUrl.isNotBlank()) {
        thumbnailUrl
    } else {
        "https://images.unsplash.com/photo-1611162617213-7d7a39e9b1d7?w=500"
    }
}

// --- SavedItemsScreen: Renders saved Videos and Reels ---
@Composable
fun SavedItemsScreen(
    viewModel: AuraViewModel,
    onBackClick: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val videosList by viewModel.videos.collectAsStateWithLifecycle()
    val reelsList by viewModel.reels.collectAsStateWithLifecycle()
    val postsList by viewModel.postsFeed.collectAsStateWithLifecycle()
    val currentUser by viewModel.currentUser.collectAsStateWithLifecycle()
    val currentUserId = currentUser?.userId ?: -1
    
    var selectedTab by remember { mutableStateOf("Videos") } // "Videos", "Reels", or "Posts"
    
    val savedVideos = remember(videosList) { videosList.filter { it.isSavedByUser } }
    val savedReels = remember(reelsList) { reelsList.filter { it.isSavedByUser } }
    val savedPosts = remember(postsList) { postsList.filter { it.isSavedByUser } }
    
    var activeViewerIndex by remember { mutableStateOf<Int?>(null) }
    
    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
            .statusBarsPadding()
    ) {
        // Toolbar Header
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 12.dp, vertical = 8.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                IconButton(onClick = onBackClick) {
                    Icon(
                        imageVector = Icons.Default.ArrowBack,
                        contentDescription = "Back",
                        tint = Color.Black
                    )
                }
                Spacer(modifier = Modifier.width(8.dp))
                Text(
                    text = "Saved Items",
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold,
                    color = Color.Black
                )
            }
            if (savedVideos.isNotEmpty() || savedReels.isNotEmpty() || savedPosts.isNotEmpty()) {
                TextButton(
                    onClick = { viewModel.clearAllSavedItems() }
                ) {
                    Icon(
                        imageVector = Icons.Default.DeleteSweep,
                        contentDescription = "Clear All",
                        tint = Color(0xFFE00052),
                        modifier = Modifier.size(18.dp)
                    )
                    Spacer(modifier = Modifier.width(4.dp))
                    Text(
                        text = "Clear All",
                        color = Color(0xFFE00052),
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }
        
        // Custom Tabs Row
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 8.dp)
                .clip(RoundedCornerShape(12.dp))
                .background(Color(0xFFF3E8FF))
                .padding(4.dp)
        ) {
            listOf("Videos", "Reels", "Posts").forEach { tab ->
                val isSelected = selectedTab == tab
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .clip(RoundedCornerShape(10.dp))
                        .background(if (isSelected) Color.White else Color.Transparent)
                        .clickable { selectedTab = tab }
                        .padding(vertical = 10.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = tab,
                        fontSize = 14.sp,
                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Medium,
                        color = if (isSelected) Color.Black else Color.Gray
                    )
                }
            }
        }
        
        // Grid lists of saved items
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .weight(1f)
        ) {
            if (selectedTab == "Videos") {
                if (savedVideos.isEmpty()) {
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(32.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        Icon(
                            imageVector = Icons.Outlined.BookmarkBorder,
                            contentDescription = null,
                            tint = Color.LightGray,
                            modifier = Modifier.size(64.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "No saved videos yet",
                            fontWeight = FontWeight.Bold,
                            fontSize = 16.sp,
                            color = Color.Gray
                        )
                    }
                } else {
                    androidx.compose.foundation.lazy.LazyColumn(
                        modifier = Modifier.fillMaxSize(),
                        contentPadding = PaddingValues(vertical = 8.dp)
                    ) {
                        itemsIndexed(savedVideos) { index, video ->
                            VideoRowItem(
                                title = video.title,
                                imageUrl = getThumbnailUrl(video.videoUrl, video.thumbnailUrl),
                                viewCount = video.viewCount,
                                timestamp = video.timestamp,
                                onDeleteClick = { viewModel.toggleVideoSave(video) },
                                onClick = { activeViewerIndex = index }
                            )
                        }
                    }
                }
            } else if (selectedTab == "Reels") {
                if (savedReels.isEmpty()) {
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(32.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        Icon(
                            imageVector = Icons.Outlined.BookmarkBorder,
                            contentDescription = null,
                            tint = Color.LightGray,
                            modifier = Modifier.size(64.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "No saved reels yet",
                            fontWeight = FontWeight.Bold,
                            fontSize = 16.sp,
                            color = Color.Gray
                        )
                    }
                } else {
                    androidx.compose.foundation.lazy.grid.LazyVerticalGrid(
                        columns = androidx.compose.foundation.lazy.grid.GridCells.Fixed(3),
                        modifier = Modifier.fillMaxSize(),
                        contentPadding = PaddingValues(12.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(savedReels.size) { index ->
                            val reel = savedReels[index]
                            SavedItemCard(
                                title = reel.title,
                                imageUrl = getThumbnailUrl(reel.videoUrl, reel.thumbnailUrl),
                                isReel = true,
                                onUnsave = { viewModel.toggleReelSave(reel) },
                                onClick = { activeViewerIndex = index }
                            )
                        }
                    }
                }
            } else {
                if (savedPosts.isEmpty()) {
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(32.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        Icon(
                            imageVector = Icons.Outlined.BookmarkBorder,
                            contentDescription = null,
                            tint = Color.LightGray,
                            modifier = Modifier.size(64.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "No saved posts yet",
                            fontWeight = FontWeight.Bold,
                            fontSize = 16.sp,
                            color = Color.Gray
                        )
                    }
                } else {
                    androidx.compose.foundation.lazy.LazyColumn(
                        modifier = Modifier.fillMaxSize(),
                        contentPadding = PaddingValues(12.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        items(savedPosts.size) { index ->
                            val post = savedPosts[index]
                            PostCard(
                                post = post,
                                viewModel = viewModel,
                                currentUserId = currentUserId
                            )
                        }
                    }
                }
            }
        }
    }
    
    // Launch Fullscreen Player
    if (activeViewerIndex != null) {
        val index = activeViewerIndex!!
        if (selectedTab == "Videos") {
            if (index < savedVideos.size) {
                FullscreenVideoReelViewer(
                    videos = savedVideos,
                    initialIndex = index,
                    isReelMode = false,
                    viewModel = viewModel,
                    onDismiss = { activeViewerIndex = null }
                )
            } else {
                activeViewerIndex = null
            }
        } else {
            if (index < savedReels.size) {
                FullscreenVideoReelViewer(
                    reels = savedReels,
                    initialIndex = index,
                    isReelMode = true,
                    viewModel = viewModel,
                    onDismiss = { activeViewerIndex = null }
                )
            } else {
                activeViewerIndex = null
            }
        }
    }
}

@Composable
