    onClick: () -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .aspectRatio(if (isReel) 9f / 16f else 1f)
            .clickable { onClick() },
        shape = RoundedCornerShape(12.dp),
