    ) {
        Box(modifier = Modifier.fillMaxSize()) {
            AsyncImage(
                model = imageUrl,
                contentDescription = null,
                modifier = Modifier.fillMaxSize(),
                contentScale = androidx.compose.ui.layout.ContentScale.Crop
            )
            // Overlay gradient for text legibility
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(
                        Brush.verticalGradient(
                            colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.7f)),
                            startY = 200f
                        )
                    )
            )
            // Save/Unsave icon at top right
            IconButton(
                onClick = onUnsave,
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(4.dp)
                    .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                    .size(32.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.Delete,
                    contentDescription = "Unsave",
                    tint = Color(0xFFE00052),
                    modifier = Modifier.size(16.dp)
                )
            }
            // Play Icon in Center
            Icon(
                imageVector = Icons.Default.PlayCircle,
                contentDescription = null,
                tint = Color.White.copy(alpha = 0.9f),
                modifier = Modifier
                    .align(Alignment.Center)
                    .size(40.dp)
            )
            // Title at Bottom Left
            Text(
                text = title,
                color = Color.White,
                fontSize = 12.sp,
                fontWeight = FontWeight.Bold,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis,
                modifier = Modifier
                    .align(Alignment.BottomStart)
                    .padding(8.dp)
            )
        }
    }
}

fun formatRealtimeCount(count: Int): String {
    if (count < 1000) return count.toString()
    val kVal = count / 1000.0
    return String.format(java.util.Locale.US, "%.1fk", kVal).replace(".0k", "k")
}

@Composable
fun VideoRowItem(
    title: String,
    imageUrl: String,
    viewCount: Int,
    timestamp: Long,
    onDeleteClick: (() -> Unit)? = null,
    onClick: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onClick() }
            .padding(horizontal = 16.dp, vertical = 6.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        // Thumbnail on the left (16:9 Aspect ratio widescreen, rounded corners)
        Card(
            modifier = Modifier
                .width(140.dp)
                .aspectRatio(16f / 9f),
            shape = RoundedCornerShape(12.dp),
            border = BorderStroke(1.dp, Color(0xFFE2E8F0))
        ) {
            Box(modifier = Modifier.fillMaxSize()) {
                AsyncImage(
                    model = imageUrl,
                    contentDescription = title,
                    modifier = Modifier.fillMaxSize(),
                    contentScale = androidx.compose.ui.layout.ContentScale.Crop
                )
                // Small Play Circle Overlay
                Box(
                    modifier = Modifier
                        .align(Alignment.Center)
                        .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                        .padding(6.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.PlayArrow,
                        contentDescription = "Play",
                        tint = Color.White,
                        modifier = Modifier.size(18.dp)
                    )
                }
            }
        }

        Spacer(modifier = Modifier.width(16.dp))

        // Title and metadata on the right
        Column(
            modifier = Modifier.weight(1f),
            verticalArrangement = Arrangement.Center
        ) {
            Text(
                text = title,
                color = Color(0xFF1E293B),
                fontSize = 15.sp,
                fontWeight = FontWeight.Bold,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis,
                lineHeight = 20.sp
            )
            Spacer(modifier = Modifier.height(6.dp))
            Row(
                verticalAlignment = Alignment.CenterVertically
            ) {
                Icon(
                    imageVector = Icons.Default.RemoveRedEye,
                    contentDescription = "Views",
                    tint = Color.Gray,
                    modifier = Modifier.size(13.dp)
                )
                Spacer(modifier = Modifier.width(4.dp))
                
                // Formatted Views
                val viewString = if (viewCount == 0) "0" else formatRealtimeCount(viewCount)
                Text(
                    text = "$viewString views",
                    color = Color.Gray,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Medium
                )
                
                Spacer(modifier = Modifier.width(6.dp))
                Text(
                    text = "•",
                    color = Color.Gray,
                    fontSize = 12.sp
                )
                Spacer(modifier = Modifier.width(6.dp))
                
                // Relative time format
                Text(
                    text = formatRelativeTime(timestamp),
                    color = Color.Gray,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Medium
                )
            }
        }

        if (onDeleteClick != null) {
            IconButton(
                onClick = onDeleteClick
            ) {
                Icon(
                    imageVector = Icons.Default.Delete,
                    contentDescription = "Delete",
                    tint = Color(0xFFE00052)
                )
            }
        }
    }
}

// --- Dynamic Fullscreen player overlay supporting swipe transition & complete comments ---
@Composable
fun FullscreenVideoReelViewer(
    videos: List<com.example.data.database.VideoEntity> = emptyList(),
    reels: List<com.example.data.database.ReelEntity> = emptyList(),
    initialIndex: Int,
    isReelMode: Boolean,
    viewModel: AuraViewModel,
    onDismiss: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    var currentIndex by remember { mutableStateOf(initialIndex) }
    val maxCount = if (isReelMode) reels.size else videos.size
    
    val allUsersList by viewModel.allUsers.collectAsStateWithLifecycle()
    var showCommentsPanel by remember { mutableStateOf(false) }
    
    // States for custom video player controls
    var isMutedState by remember { mutableStateOf(false) }
    var isPausedState by remember { mutableStateOf(false) }
    var seekTriggerState by remember { mutableStateOf(0) }
    var seekAmountMsState by remember { mutableStateOf(0) }
    
    // Modern player state enhancements
    var currentProgressMs by remember { mutableStateOf(0) }
    var totalDurationMs by remember { mutableStateOf(0) }
    var seekTargetPosition by remember { mutableStateOf(-1) }

    var showSettingsDialog by remember { mutableStateOf(false) }
    var selectedResolution by remember { mutableStateOf("1080p") }
    var selectedSpeed by remember { mutableStateOf(1.0f) }

    // Custom media reaction states & emoji animation logic
    var showMediaReactionsPanel by remember { mutableStateOf(false) }
    var mediaFloatingEmojis by remember { mutableStateOf(emptyList<FloatingEmoji>()) }
    LaunchedEffect(mediaFloatingEmojis) {
        if (mediaFloatingEmojis.isNotEmpty()) {
            delay(16)
            mediaFloatingEmojis = mediaFloatingEmojis.map { 
                it.copy(yOffset = it.yOffset - 6f) 
            }.filter { it.yOffset > -500f }
        }
    }

    val triggerMediaBurstEmojis = remember {
        { emoji: String ->
            val count = (8..12).random()
            val list = (1..count).map {
                FloatingEmoji(
                    id = System.nanoTime() + (0..9999).random(),
                    emoji = emoji,
                    xOffset = (-100..100).random().toFloat(),
                    yOffset = (-80..-20).random().toFloat()
                )
            }
            mediaFloatingEmojis = mediaFloatingEmojis + list
        }
    }

    // Helper to extract numeric ID from various share formats
    val extractIdFromQuery = remember {
        { query: String ->
            // 1. Try to find any pattern of alphanumeric/dash followed by underscore then digits (the ID)
            val regex = Regex("([a-zA-Z0-9\\-]+)_([0-9]+)")
            val match = regex.find(query)
            if (match != null) {
                match.groupValues[2].toIntOrNull()
            } else {
                // 2. Try URI patterns: aura://video/12 or aura://reel/12
                val uriRegex = Regex("(video|reel)/([0-9a-zA-Z\\-]+_)?([0-9]+)")
                val uriMatch = uriRegex.find(query)
                if (uriMatch != null) {
                    uriMatch.groupValues[3].toIntOrNull()
                } else {
                    // 3. Just find any numeric part or split
                    val parts = query.split("_", "/", " ", ":", "\n")
                    var foundId: Int? = null
                    for (part in parts.reversed()) {
                        val cleanedPart = part.trim()
                        val num = cleanedPart.toIntOrNull()
                        if (num != null) {
                            foundId = num
                            break
                        }
                    }
                    foundId
                }
            }
        }
    }

    // Control visibility state (2-second auto-hide)
    var showControls by remember { mutableStateOf(true) }
    
    // Search query state
    var searchQuery by remember { mutableStateOf("") }
    
    // Keep bounds safe
    if (currentIndex < 0) currentIndex = 0
    if (currentIndex >= maxCount) currentIndex = maxCount - 1
    
    if (maxCount == 0) {
        onDismiss()
        return
    }
    
    val activeVideo = if (!isReelMode) videos.getOrNull(currentIndex) else null
    val activeReel = if (isReelMode) reels.getOrNull(currentIndex) else null

    val authorId = activeVideo?.authorId ?: activeReel?.authorId ?: 0
    val authorName = activeVideo?.authorName ?: activeReel?.authorName ?: "Aura User"
    val authorAvatar = activeVideo?.authorAvatar ?: activeReel?.authorAvatar ?: ""
    val title = activeVideo?.title ?: activeReel?.title ?: ""
    val description = activeVideo?.description ?: activeReel?.description ?: ""
    val tags = activeVideo?.tags ?: activeReel?.tags ?: ""
    val videoUrl = activeVideo?.videoUrl ?: activeReel?.videoUrl ?: ""

    LaunchedEffect(currentIndex, isReelMode) {
        // Reset player states on item change
        isPausedState = false
        currentProgressMs = 0
        totalDurationMs = 0
        seekTargetPosition = -1
        if (isReelMode) {
            activeReel?.let { viewModel.incrementReelView(it) }
        } else {
            activeVideo?.let { viewModel.incrementVideoView(it) }
        }
    }
    
    // Auto-hide effect: hides controls after 2 seconds if video is playing
    LaunchedEffect(showControls, isPausedState) {
        if (showControls && !isPausedState) {
            delay(2000)
            showControls = false
        }
    }
    
    // Robust query pasting search trigger using the custom extractIdFromQuery helper
    LaunchedEffect(searchQuery) {
        if (searchQuery.isNotBlank()) {
            val cleaned = searchQuery.trim()
            val targetId = extractIdFromQuery(cleaned)
            if (targetId != null) {
                if (isReelMode) {
                    val index = reels.indexOfFirst { it.reelId == targetId }
                    if (index != -1) {
                        currentIndex = index
                        searchQuery = ""
                        android.widget.Toast.makeText(context, "রিল খুঁজে পাওয়া গেছে! প্লে করা হচ্ছে... 🎬💜", android.widget.Toast.LENGTH_SHORT).show()
                    } else {
                        android.widget.Toast.makeText(context, "রিলটি খুঁজে পাওয়া যায়নি! 🔍", android.widget.Toast.LENGTH_SHORT).show()
                    }
                } else {
                    val index = videos.indexOfFirst { it.videoId == targetId }
                    if (index != -1) {
                        currentIndex = index
                        searchQuery = ""
                        android.widget.Toast.makeText(context, "ভিডিও খুঁজে পাওয়া গেছে! প্লে করা হচ্ছে... 🎬💜", android.widget.Toast.LENGTH_SHORT).show()
                    } else {
                        android.widget.Toast.makeText(context, "ভিডিওটি খুঁজে পাওয়া যায়নি! 🔍", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }
    
    val isLiked = activeVideo?.isLikedByUser ?: activeReel?.isLikedByUser ?: false
    val activeUserReaction = if (isReelMode) (activeReel?.userReaction ?: "") else (activeVideo?.userReaction ?: "")
    val isSaved = activeVideo?.isSavedByUser ?: activeReel?.isSavedByUser ?: false
    val likeCount = activeVideo?.likeCount ?: activeReel?.likeCount ?: 0
    val commentCount = activeVideo?.commentCount ?: activeReel?.commentCount ?: 0
    val shareCount = activeVideo?.shareCount ?: activeReel?.shareCount ?: 0
    
    var totalDragY by remember { mutableStateOf(0f) }
    
    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.Black)
            .statusBarsPadding()
            .navigationBarsPadding()
            .pointerInput(currentIndex) {
                detectDragGestures(
                    onDragStart = { totalDragY = 0f },
                    onDragEnd = {
                        if (totalDragY < -120f) { // Swipe Up (Next)
                            if (currentIndex < maxCount - 1) {
                                currentIndex++
                            } else {
                                android.widget.Toast.makeText(context, "শেষ ভিডিওতে পৌঁছেছেন 🎬", android.widget.Toast.LENGTH_SHORT).show()
                            }
                        } else if (totalDragY > 120f) { // Swipe Down (Prev)
                            if (currentIndex > 0) {
                                currentIndex--
                            } else {
                                android.widget.Toast.makeText(context, "প্রথম ভিডিওতে আছেন 🎬", android.widget.Toast.LENGTH_SHORT).show()
                            }
                        }
                        totalDragY = 0f
                    },
                    onDragCancel = { totalDragY = 0f },
                    onDrag = { change, dragAmount ->
                        change.consume()
                        totalDragY += dragAmount.y
                    }
                )
            }
    ) {
        AnimatedContent(
            targetState = currentIndex,
            transitionSpec = {
                if (targetState > initialState) {
                    (slideInVertically(animationSpec = tween(400)) { height -> height } + fadeIn(animationSpec = tween(400)))
                        .togetherWith(slideOutVertically(animationSpec = tween(400)) { height -> -height } + fadeOut(animationSpec = tween(400)))
                } else {
                    (slideInVertically(animationSpec = tween(400)) { height -> -height } + fadeIn(animationSpec = tween(400)))
                        .togetherWith(slideOutVertically(animationSpec = tween(400)) { height -> height } + fadeOut(animationSpec = tween(400)))
                }
            },
            label = "VideoSwipeTransition",
            modifier = Modifier.fillMaxSize()
        ) { targetIndex ->
            val activeVideo = if (!isReelMode) videos.getOrNull(targetIndex) else null
            val activeReel = if (isReelMode) reels.getOrNull(targetIndex) else null

            val authorId = activeVideo?.authorId ?: activeReel?.authorId ?: 0
            val authorName = activeVideo?.authorName ?: activeReel?.authorName ?: "Aura User"
            val authorAvatar = activeVideo?.authorAvatar ?: activeReel?.authorAvatar ?: ""
            val title = activeVideo?.title ?: activeReel?.title ?: ""
            val description = activeVideo?.description ?: activeReel?.description ?: ""
            val tags = activeVideo?.tags ?: activeReel?.tags ?: ""
            val videoUrl = activeVideo?.videoUrl ?: activeReel?.videoUrl ?: ""

            val isLiked = activeVideo?.isLikedByUser ?: activeReel?.isLikedByUser ?: false
            val activeUserReaction = if (isReelMode) (activeReel?.userReaction ?: "") else (activeVideo?.userReaction ?: "")
            val isSaved = activeVideo?.isSavedByUser ?: activeReel?.isSavedByUser ?: false
            val likeCount = activeVideo?.likeCount ?: activeReel?.likeCount ?: 0
            val commentCount = activeVideo?.commentCount ?: activeReel?.commentCount ?: 0
            val shareCount = activeVideo?.shareCount ?: activeReel?.shareCount ?: 0

            Box(modifier = Modifier.fillMaxSize()) {
                // --- Video Player view and touch listener layer ---
                Box(modifier = Modifier.fillMaxSize()) {
            if (videoUrl.isNotBlank()) {
                AuraVideoPlayer(
                    videoPath = videoUrl,
                    modifier = Modifier.fillMaxSize(),
                    isMute = isMutedState,
                    isLooping = true,
                    isPaused = isPausedState,
                    seekTrigger = seekTriggerState,
                    seekAmountMs = seekAmountMsState,
                    absoluteSeekMs = seekTargetPosition,
                    playbackSpeed = selectedSpeed,
                    onProgressUpdate = { curr, dur ->
                        currentProgressMs = curr
                        totalDurationMs = dur
                        seekTargetPosition = -1
                    }
                )
            } else {
                // Fallback thumbnail if empty video uri
                val thumb = getThumbnailUrl(videoUrl, activeVideo?.thumbnailUrl ?: activeReel?.thumbnailUrl ?: "")
                AsyncImage(
                    model = thumb,
                    contentDescription = null,
                    modifier = Modifier.fillMaxSize(),
                    contentScale = androidx.compose.ui.layout.ContentScale.Fit
                )
            }

            // Transparent layer covering the player that toggles control visibility on tap
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .clickable(
                        interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() },
                        indication = null
                    ) {
                        showControls = !showControls
                    }
            )
        }
        
        // --- Custom Rising Floating Emojis Reaction Overlay ---
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.BottomEnd) {
            mediaFloatingEmojis.forEach { fe ->
                Box(
                    modifier = Modifier
                        .padding(end = 50.dp, bottom = 120.dp) // Start rising from next to the Like/Love buttons
                        .offset(x = fe.xOffset.dp, y = fe.yOffset.dp)
                ) {
                    Text(text = fe.emoji, fontSize = 32.sp)
                }
            }
        }

        // --- Immersive Controls Overlay (Wraps everything and auto-hides after 2s inactivity) ---
        androidx.compose.animation.AnimatedVisibility(
            visible = showControls,
            enter = androidx.compose.animation.fadeIn(),
            exit = androidx.compose.animation.fadeOut(),
            modifier = Modifier.fillMaxSize()
        ) {
            Box(modifier = Modifier.fillMaxSize()) {
                
                // --- Split background shadow overlays ---
                // Top Overlay Shadow
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(110.dp)
                        .align(Alignment.TopCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(Color.Black.copy(alpha = 0.5f), Color.Transparent)
                            )
                        )
                )
                // Bottom Overlay Shadow
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(230.dp)
                        .align(Alignment.BottomCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.75f))
                            )
                        )
                )
                
                // --- Top Row: Close icon, modern Search bar with Paste option ---
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(top = 16.dp, start = 16.dp, end = 16.dp)
                        .align(Alignment.TopCenter),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier.background(Color.Black.copy(alpha = 0.5f), CircleShape)
                    ) {
                        Icon(Icons.Default.Close, contentDescription = "Close", tint = Color.White)
                    }

                    // M3 Search OutlinedTextField with Paste shortcut button
                    OutlinedTextField(
                        value = searchQuery,
                        onValueChange = { searchQuery = it },
                        placeholder = { Text("Paste Reel/Video ID here...", color = Color.LightGray, fontSize = 12.sp) },
                        modifier = Modifier
                            .weight(1f)
                            .height(48.dp),
                        singleLine = true,
                        colors = TextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedContainerColor = Color.Black.copy(alpha = 0.4f),
                            unfocusedContainerColor = Color.Black.copy(alpha = 0.4f),
                            focusedIndicatorColor = LavenderPrimary,
                            unfocusedIndicatorColor = Color.Gray
                        ),
                        shape = RoundedCornerShape(24.dp),
                        leadingIcon = {
                            Icon(Icons.Default.Search, contentDescription = "Search", tint = Color.White, modifier = Modifier.size(18.dp))
                        },
                        trailingIcon = {
                            if (searchQuery.isNotEmpty()) {
                                IconButton(onClick = { searchQuery = "" }) {
                                    Icon(Icons.Default.Clear, contentDescription = "Clear", tint = Color.White, modifier = Modifier.size(18.dp))
                                }
                            } else {
                                IconButton(
                                    onClick = {
                                        try {
                                            val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                            val clipData = clipboard.primaryClip
                                            if (clipData != null && clipData.itemCount > 0) {
                                                val text = clipData.getItemAt(0).text?.toString() ?: ""
                                                searchQuery = text
                                            }
                                        } catch (e: Exception) {}
                                    }
                                ) {
                                    Icon(Icons.Default.ContentPaste, contentDescription = "Paste", tint = LavenderPrimary, modifier = Modifier.size(18.dp))
                                }
                            }
                        }
                    )
                }
                
                // --- Centered Interactive Playback Controls (Double click / tap simulation) ---
                Row(
                    modifier = Modifier.align(Alignment.Center),
                    horizontalArrangement = Arrangement.spacedBy(28.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    // Rewind 5 seconds
                    IconButton(
                        onClick = {
                            seekAmountMsState = -5000
                            seekTriggerState++
                        },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.45f), CircleShape)
                            .size(52.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.FastRewind,
                            contentDescription = "Rewind 5s",
                            tint = Color.White,
                            modifier = Modifier.size(26.dp)
                        )
                    }

                    // Play / Pause Button
                    IconButton(
                        onClick = { isPausedState = !isPausedState },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.55f), CircleShape)
                            .size(68.dp)
                    ) {
                        Icon(
                            imageVector = if (isPausedState) Icons.Default.PlayArrow else Icons.Default.Pause,
                            contentDescription = if (isPausedState) "Play" else "Pause",
                            tint = Color.White,
                            modifier = Modifier.size(38.dp)
                        )
                    }

                    // Fast Forward 5 seconds
                    IconButton(
                        onClick = {
                            seekAmountMsState = 5000
                            seekTriggerState++
                        },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.45f), CircleShape)
                            .size(52.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.FastForward,
                            contentDescription = "Fast Forward 5s",
                            tint = Color.White,
                            modifier = Modifier.size(26.dp)
                        )
                    }
                }
                
                // --- Bottom Area: Creator info, Title, Description, Hashtags & Progress Slider Row ---
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.BottomStart)
                        .padding(start = 16.dp, end = 80.dp, bottom = 16.dp)
                ) {
                    // Creator info row - Clicking avatar or name navigates directly to user profile
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier
                            .clip(RoundedCornerShape(8.dp))
                            .clickable {
                                val matched = allUsersList.find { it.userId == authorId || it.displayName == authorName }
                                if (matched != null) {
                                    onDismiss()
                                    viewModel.navigateTo(Screen.ProfileDetail(matched))
                                } else {
                                    // Create a temporary UserEntity to view public profile dashboard
                                    val tempUser = com.example.data.database.UserEntity(
                                        userId = authorId,
                                        username = authorName.lowercase().replace(" ", "_"),
                                        displayName = authorName,
                                        avatarUrl = authorAvatar,
                                        coverUrl = "",
                                        bio = "Aura Creator"
                                    )
                                    onDismiss()
                                    viewModel.navigateTo(Screen.ProfileDetail(tempUser))
                                }
                            }
                            .padding(4.dp)
                    ) {
                        ProfileAvatar(avatarId = authorAvatar, size = 40)
                        Spacer(modifier = Modifier.width(8.dp))
                        Column {
                            Text(
                                text = authorName,
                                color = Color.White,
                                fontWeight = FontWeight.Bold,
                                fontSize = 15.sp
                            )
                            Text(
                                text = "Follow",
                                color = LavenderPrimary,
                                fontWeight = FontWeight.SemiBold,
                                fontSize = 12.sp
                            )
                        }
                    }
                    
                    Spacer(modifier = Modifier.height(10.dp))
                    
                    Text(
                        text = title,
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 16.sp
                    )

                    // Dynamic See more / See less for description and tags
                    var isExpanded by remember { mutableStateOf(false) }
                    val fullText = buildString {
                        if (description.isNotBlank()) append(description)
                        if (tags.isNotBlank()) {
                            if (isNotEmpty()) append("\n")
                            append(tags)
                        }
                    }
                    if (fullText.isNotBlank()) {
                        Spacer(modifier = Modifier.height(4.dp))
                        val isLongText = fullText.length > 80
                        val displayText = if (isExpanded || !isLongText) {
                            fullText
                        } else {
                            fullText.take(80) + "..."
                        }
                        Column {
                            Text(
                                text = displayText,
                                color = Color.White.copy(alpha = 0.9f),
                                fontSize = 13.sp,
                                lineHeight = 18.sp
                            )
                            if (isLongText) {
                                Text(
                                    text = if (isExpanded) "See less" else "See more",
                                    color = LavenderPrimary,
                                    fontSize = 13.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .clickable { isExpanded = !isExpanded }
                                        .padding(vertical = 4.dp)
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // --- Progress Bar Slider & Timer Row (Facebook 2026 Style) ---
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        val formatTime = { ms: Int ->
                            val totalSecs = ms / 1000
                            val mins = totalSecs / 60
                            val secs = totalSecs % 60
                            String.format(java.util.Locale.US, "%02d:%02d", mins, secs)
                        }

                        Text(
                            text = formatTime(currentProgressMs),
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Slider(
                            value = currentProgressMs.toFloat(),
                            onValueChange = { newValue ->
                                currentProgressMs = newValue.toInt()
                            },
                            onValueChangeFinished = {
                                seekTargetPosition = currentProgressMs
                                seekTriggerState++
                            },
                            valueRange = 0f..(if (totalDurationMs > 0) totalDurationMs.toFloat() else 100f),
                            colors = SliderDefaults.colors(
                                thumbColor = LavenderPrimary,
                                activeTrackColor = LavenderPrimary,
                                inactiveTrackColor = Color.White.copy(alpha = 0.3f),
                                activeTickColor = Color.Transparent,
                                inactiveTickColor = Color.Transparent
                            ),
                            modifier = Modifier
                                .weight(1f)
                                .height(24.dp)
                                .padding(horizontal = 8.dp)
                        )

                        Text(
                            text = formatTime(totalDurationMs),
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Spacer(modifier = Modifier.width(8.dp))

                        // Player Settings Icon Button (Resolution, Speed, Captions)
                        IconButton(
                            onClick = { showSettingsDialog = true },
                            modifier = Modifier.size(28.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Settings,
                                contentDescription = "Player Settings",
                                tint = Color.White,
                                modifier = Modifier.size(18.dp)
                            )
                        }
                    }
                }
                
                // --- Vertical Action Buttons Column at Bottom Right (Real-time Counts below) ---
                Column(
                    modifier = Modifier
                        .align(Alignment.BottomEnd)
                        .padding(end = 12.dp, bottom = 24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    val context = androidx.compose.ui.platform.LocalContext.current

                    // Like Button & Count (with combinedClickable for tap & long-press)
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Box(
                            modifier = Modifier
                                .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                                .size(46.dp)
                                .clip(CircleShape)
                                .combinedClickable(
                                    onClick = {
                                        if (isReelMode) {
                                            activeReel?.let { viewModel.toggleReelLike(it) }
                                        } else {
                                            activeVideo?.let { viewModel.toggleVideoLike(it) }
                                        }
                                        triggerMediaBurstEmojis(if (isReelMode) "❤️" else "👍")
                                    },
                                    onLongClick = {
                                        showMediaReactionsPanel = true
                                    }
                                ),
                            contentAlignment = Alignment.Center
                        ) {
                            if (activeUserReaction.isNotBlank()) {
                                Text(
                                    text = activeUserReaction,
                                    fontSize = 24.sp
                                )
                            } else {
                                Icon(
                                    imageVector = if (isReelMode) {
                                        if (isLiked) Icons.Filled.Favorite else Icons.Outlined.FavoriteBorder
                                    } else {
                                        if (isLiked) Icons.Filled.ThumbUp else Icons.Outlined.ThumbUp
                                    },
                                    contentDescription = "Like",
                                    tint = if (isLiked) {
                                        if (isReelMode) Color.Red else LavenderPrimary
                                    } else {
                                        Color.White
                                    },
                                    modifier = Modifier.size(24.dp)
                                )
                            }
                        }

                        // Media Reactions Popup positioned beautifully to the left of the Like button
                        if (showMediaReactionsPanel) {
                            androidx.compose.ui.window.Popup(
                                alignment = Alignment.TopStart,
                                offset = androidx.compose.ui.unit.IntOffset(x = -320, y = -10),
                                onDismissRequest = { showMediaReactionsPanel = false }
                            ) {
                                Card(
                                    modifier = Modifier
                                        .shadow(8.dp, RoundedCornerShape(32.dp))
                                        .border(1.dp, LavenderPrimary.copy(alpha = 0.5f), RoundedCornerShape(32.dp)),
                                    colors = CardDefaults.cardColors(containerColor = Color.White),
                                    shape = RoundedCornerShape(32.dp)
                                ) {
                                    Row(
                                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 6.dp),
                                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        val emojiList = listOf("👍", "❤️", "🥰", "😄", "😮", "😢", "😡")
                                        emojiList.forEach { emoji ->
                                            var isClickedState by remember { mutableStateOf(false) }
                                            val emojiScale by animateFloatAsState(
                                                targetValue = if (isClickedState) 1.5f else 1.0f
                                            )
                                            Box(
                                                modifier = Modifier
                                                    .graphicsLayer(scaleX = emojiScale, scaleY = emojiScale)
                                                    .clickable {
                                                        isClickedState = true
                                                        if (isReelMode) {
                                                            activeReel?.let {
                                                                viewModel.setReelReaction(it, emoji)
                                                            }
                                                        } else {
                                                            activeVideo?.let {
                                                                viewModel.setVideoReaction(it, emoji)
                                                            }
                                                        }
                                                        triggerMediaBurstEmojis(emoji)
                                                        android.widget.Toast.makeText(context, "Smashed reaction $emoji ! ✨💜", android.widget.Toast.LENGTH_SHORT).show()
                                                        showMediaReactionsPanel = false
                                                    }
                                                    .padding(4.dp),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text(
                                                    text = emoji,
                                                    fontSize = 22.sp
                                                )
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = formatRealtimeCount(likeCount),
                            color = Color.White,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    
                    // Comment Button & Count
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        IconButton(
                            onClick = { showCommentsPanel = true },
                            modifier = Modifier
                                .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                                .size(46.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Outlined.ChatBubbleOutline,
                                contentDescription = "Comments",
                                tint = Color.White,
                                modifier = Modifier.size(22.dp)
                            )
                        }
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = formatRealtimeCount(commentCount),
                            color = Color.White,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    
                    // Share Button & Count
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        IconButton(
                            onClick = {
                                try {
                                    val authorUid = viewModel.getUserResolvedUid(authorId)
                                    val shareIntent = android.content.Intent().apply {
                                        action = android.content.Intent.ACTION_SEND
                                        type = "text/plain"
                                        val itemId = if (isReelMode) (activeReel?.reelId ?: 0) else (activeVideo?.videoId ?: 0)
                                        val shareText = if (isReelMode) {
                                            "Check out this amazing Reel on Aura! 🎬💜\n\nTitle: \"$title\"\nBy: $authorName\n\nCopy and paste this ID into the Aura Video Search bar to play direct:\nID: ${authorUid}_$itemId\n\nJoin Aura - Connecting creators worldwide with love! ✨"
                                        } else {
                                            "Check out this amazing Video on Aura! 📺💜\n\nTitle: \"$title\"\nBy: $authorName\n\nCopy and paste this ID into the Aura Video Search bar to play direct:\nID: ${authorUid}_$itemId\n\nJoin Aura - Connecting creators worldwide with love! ✨"
                                        }
                                        putExtra(android.content.Intent.EXTRA_TEXT, shareText)
                                    }
                                    val chooser = android.content.Intent.createChooser(shareIntent, "Share")
                                    chooser.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                                    context.startActivity(chooser)
                                    
                                    // Increment share count in Room/UI
                                    if (isReelMode) {
                                        activeReel?.let { viewModel.incrementReelShare(it) }
                                    } else {
                                        activeVideo?.let { viewModel.incrementVideoShare(it) }
                                    }
                                } catch (e: Exception) {
                                    android.widget.Toast.makeText(context, "Could not open share dialog!", android.widget.Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier
                                .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                                .size(46.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Outlined.Share,
                                contentDescription = "Share",
                                tint = Color.White,
                                modifier = Modifier.size(22.dp)
                            )
                        }
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = formatRealtimeCount(shareCount),
                            color = Color.White,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    // Sound Mute/Unmute Button
                    IconButton(
                        onClick = { isMutedState = !isMutedState },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                            .size(46.dp)
                    ) {
                        Icon(
                            imageVector = if (isMutedState) Icons.Default.VolumeOff else Icons.Default.VolumeUp,
                            contentDescription = if (isMutedState) "Unmute" else "Mute",
                            tint = Color.White,
                            modifier = Modifier.size(22.dp)
                        )
                    }
                    
                    // Save Button
                    IconButton(
                        onClick = {
                            if (isReelMode) {
                                activeReel?.let { viewModel.toggleReelSave(it) }
                            } else {
                                activeVideo?.let { viewModel.toggleVideoSave(it) }
                            }
                        },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                            .size(46.dp)
                    ) {
                        Icon(
                            imageVector = if (isSaved) Icons.Filled.Bookmark else Icons.Outlined.BookmarkBorder,
                            contentDescription = "Save",
                            tint = if (isSaved) LavenderPrimary else Color.White,
                            modifier = Modifier.size(22.dp)
                        )
                    }

                    // Three-Dot Settings dialog button
                    var showThreeDotDialog by remember { mutableStateOf(false) }
                    IconButton(
                        onClick = { showThreeDotDialog = true },
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                            .size(46.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.MoreVert,
                            contentDescription = "More Options",
                            tint = Color.White,
                            modifier = Modifier.size(22.dp)
                        )
                    }

                    if (showThreeDotDialog) {
                        androidx.compose.ui.window.Dialog(onDismissRequest = { showThreeDotDialog = false }) {
                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF1E1E24)),
                                shape = RoundedCornerShape(24.dp),
                                modifier = Modifier
                                    .padding(vertical = 32.dp, horizontal = 16.dp)
                                    .fillMaxWidth()
                                    .fillMaxHeight(0.85f)
                            ) {
                                Column(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .padding(16.dp)
                                ) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Text(
                                            text = "Videos + Reels Options",
                                            color = Color.White,
                                            fontSize = 18.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        IconButton(onClick = { showThreeDotDialog = false }) {
                                            Icon(Icons.Default.Close, contentDescription = "Close", tint = Color.White)
                                        }
                                    }
                                    Spacer(modifier = Modifier.height(12.dp))

                                    androidx.compose.foundation.lazy.LazyColumn(
                                        modifier = Modifier.weight(1f),
                                        verticalArrangement = Arrangement.spacedBy(10.dp)
                                    ) {
                                        // Why am I seeing this videos/reels section
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                Column(modifier = Modifier.padding(16.dp)) {
                                                    Text(
                                                        text = "Why am I seeing this Videos + Reels?",
                                                        color = Color.LightGray,
                                                        fontSize = 13.sp,
                                                        fontWeight = FontWeight.Bold
                                                    )
                                                    Spacer(modifier = Modifier.height(4.dp))
                                                    Text(
                                                        text = "You're friends with $authorName",
                                                        color = Color.White,
                                                        fontSize = 14.sp,
                                                        fontWeight = FontWeight.Bold
                                                    )
                                                }
                                            }
                                        }

                                        // Group 1: Interested / Not interested
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                Column {
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.AddCircle,
                                                        title = "Interested",
                                                        subtitle = "More of your videos/reels will be like this.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            android.widget.Toast.makeText(context, "More of your videos/reels will be like this", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                    Divider(color = Color.Gray.copy(alpha = 0.2f))
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.RemoveCircle,
                                                        title = "Not interested",
                                                        subtitle = "Less of your videos/reels will be like this.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            android.widget.Toast.makeText(context, "Less of your videos/reels will be like this", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                }
                                            }
                                        }

                                        // Group 2: Save, Hide, Notifs
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                Column {
                                                    BottomSheetOptionRow(
                                                        icon = if (isSaved) Icons.Default.Bookmark else Icons.Default.BookmarkBorder,
                                                        title = if (isSaved) "Unsave video/reel" else "Save video/reel",
                                                        subtitle = if (isSaved) "Remove this from your saved items." else "Add this to your saved items.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            if (isReelMode) {
                                                                activeReel?.let { viewModel.toggleReelSave(it) }
                                                            } else {
                                                                activeVideo?.let { viewModel.toggleVideoSave(it) }
                                                            }
                                                            if (isSaved) {
                                                                android.widget.Toast.makeText(context, "Video/Reel removed from saved items", android.widget.Toast.LENGTH_LONG).show()
                                                            } else {
                                                                android.widget.Toast.makeText(context, "Add this to your saved items", android.widget.Toast.LENGTH_LONG).show()
                                                            }
                                                        }
                                                    )
                                                    Divider(color = Color.Gray.copy(alpha = 0.2f))
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.VisibilityOff,
                                                        title = "Hide video/reel",
                                                        subtitle = "See fewer videos/reels like this.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            onDismiss()
                                                            android.widget.Toast.makeText(context, "See fewer videos/reels like this", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                    Divider(color = Color.Gray.copy(alpha = 0.2f))
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.Notifications,
                                                        title = "Turn on notifications for this video/reel",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            android.widget.Toast.makeText(context, "Turned on notifications for this video/reel", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                }
                                            }
                                        }

                                        // Group 3: Favorites, Snooze, Unfollow
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                Column {
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.Star,
                                                        title = "Add $authorName to Favorites",
                                                        subtitle = "Prioritize his videos/reels in Feed.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            android.widget.Toast.makeText(context, "Prioritize his videos/reels in Feed", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                    Divider(color = Color.Gray.copy(alpha = 0.2f))
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.AccessTime,
                                                        title = "Snooze $authorName for 30 days",
                                                        subtitle = "Temporarily stop seeing videos/reels.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            onDismiss()
                                                            android.widget.Toast.makeText(context, "Temporarily stop seeing videos/reels", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                    Divider(color = Color.Gray.copy(alpha = 0.2f))
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.PersonOutline,
                                                        title = "Unfollow $authorName",
                                                        subtitle = "Stop seeing videos/reels but stay friends. They won't be notified that you unfollowed...",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            onDismiss()
                                                            android.widget.Toast.makeText(context, "Stop seeing videos/reels but stay friends. They won't be notified that you unfollowed...", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                }
                                            }
                                        }

                                        // Group 4: Block
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                Column {
                                                    BottomSheetOptionRow(
                                                        icon = Icons.Default.Block,
                                                        title = "Block $authorName's profile",
                                                        subtitle = "You won't be able to see or contact each other.",
                                                        onClick = { 
                                                            showThreeDotDialog = false
                                                            onDismiss()
                                                            android.widget.Toast.makeText(context, "You won't be able to see or contact each other", android.widget.Toast.LENGTH_LONG).show()
                                                        }
                                                    )
                                                }
                                            }
                                        }

                                        // Additional Group: Direct search ID Utility
                                        item {
                                            Card(
                                                modifier = Modifier.fillMaxWidth(),
                                                colors = CardDefaults.cardColors(containerColor = Color.DarkGray.copy(alpha = 0.3f))
                                            ) {
                                                BottomSheetOptionRow(
                                                    icon = Icons.Default.ContentCopy,
                                                    title = "Copy direct ID",
                                                    subtitle = "Copy direct media ID to search inside Aura",
                                                    onClick = { 
                                                        showThreeDotDialog = false
                                                        val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                                        val itemId = if (isReelMode) (activeReel?.reelId ?: 0) else (activeVideo?.videoId ?: 0)
                                                        val linkText = "${viewModel.getUserResolvedUid(authorId)}_$itemId"
                                                        val clip = android.content.ClipData.newPlainText("video_link", linkText)
                                                        clipboard.setPrimaryClip(clip)
                                                        android.widget.Toast.makeText(context, "Direct search ID copied to clipboard! 📋🔗", android.widget.Toast.LENGTH_SHORT).show()
                                                    }
                                                )
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
            }
            }
        }
        
        // --- Custom Player Settings Dialog (Resolution, Playback Speed, Auto Captions) ---
        if (showSettingsDialog) {
            androidx.compose.ui.window.Dialog(onDismissRequest = { showSettingsDialog = false }) {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF191720)),
                    shape = RoundedCornerShape(20.dp),
                    modifier = Modifier
                        .padding(16.dp)
                        .fillMaxWidth()
                ) {
                    Column(
                        modifier = Modifier
                            .padding(20.dp)
                    ) {
                        Text(
                            text = "Aura Player 2026 Settings",
                            color = Color.White,
                            fontSize = 18.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        
                        // 1. Resolution Selection (Horizontal Scrollable Row)
                        Text(
                            text = "Video Resolution",
                            color = LavenderPrimary,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        val resolutions = listOf("240p", "480p", "720p", "1080p", "1440p", "2160p")
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .horizontalScroll(rememberScrollState()),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            resolutions.forEach { res ->
                                val isSel = selectedResolution == res
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(16.dp))
                                        .background(if (isSel) LavenderPrimary else Color.White.copy(alpha = 0.1f))
                                        .clickable {
                                            selectedResolution = res
                                            android.widget.Toast.makeText(context, "Resolution set to $res • Aura Live Optimization Active! ✨", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                        .padding(horizontal = 12.dp, vertical = 6.dp)
                                ) {
                                    Text(text = res, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Medium)
                                }
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(18.dp))
                        
                        // 2. Playback Speed Selection (Horizontal Scrollable Row)
                        Text(
                            text = "Playback Speed",
                            color = LavenderPrimary,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        val speeds = listOf(
                            0.5f to "0.5x",
                            0.8f to "0.8x",
                            1.0f to "1.0x",
                            2.0f to "2.0x",
                            4.0f to "4.0x"
                        )
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .horizontalScroll(rememberScrollState()),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            speeds.forEach { (speedVal, label) ->
                                val isSel = selectedSpeed == speedVal
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(16.dp))
                                        .background(if (isSel) LavenderPrimary else Color.White.copy(alpha = 0.1f))
                                        .clickable {
                                            selectedSpeed = speedVal
                                            android.widget.Toast.makeText(context, "Playback speed: $label 🎬", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                        .padding(horizontal = 12.dp, vertical = 6.dp)
                                ) {
                                    Text(text = label, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Medium)
                                }
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(22.dp))
                        
                        // Close Settings Button
                        Button(
                            onClick = { showSettingsDialog = false },
                            colors = ButtonDefaults.buttonColors(containerColor = LavenderPrimary),
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Text("Apply & Close", color = Color.White, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }
        
        // --- Comments Panel Bottom Sheet Overlay ---
        if (showCommentsPanel) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(Color.Black.copy(alpha = 0.4f))
                    .clickable { showCommentsPanel = false }
            ) {
                Box(
                    modifier = Modifier
                        .align(Alignment.BottomCenter)
                        .clickable(enabled = false) {}
                ) {
                    VideoReelCommentsPanel(
                        videoId = activeVideo?.videoId,
                        reelId = activeReel?.reelId,
                        viewModel = viewModel,
                        onDismiss = { showCommentsPanel = false }
                    )
                }
            }
        }
    }
}

@Composable
fun VideoReelCommentsPanel(
    videoId: Int?,
    reelId: Int?,
    viewModel: AuraViewModel,
    onDismiss: () -> Unit
) {
    val comments = if (videoId != null) {
        viewModel.getVideoCommentsFlow(videoId).collectAsState(initial = emptyList()).value
    } else if (reelId != null) {
        viewModel.getReelCommentsFlow(reelId).collectAsState(initial = emptyList()).value
    } else {
        emptyList()
    }

    var commentText by remember { mutableStateOf("") }

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .fillMaxHeight(0.55f)
            .background(Color.White, RoundedCornerShape(topStart = 20.dp, topEnd = 20.dp))
            .padding(16.dp)
    ) {
        Column(modifier = Modifier.fillMaxSize()) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "Comments (${comments.size})",
                    fontWeight = FontWeight.Bold,
                    fontSize = 16.sp,
                    color = Color.Black
                )
                IconButton(onClick = onDismiss) {
                    Icon(Icons.Default.Close, contentDescription = "Close", tint = Color.Gray)
                }
            }
            Spacer(modifier = Modifier.height(12.dp))
            LazyColumn(
                modifier = Modifier.weight(1f).fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                if (comments.isEmpty()) {
                    item {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(32.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("No comments yet. Be the first to comment! 💬", color = Color.Gray, fontSize = 13.sp)
                        }
                    }
                } else {
                    items(comments) { comment ->
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.Top
                        ) {
                            val avatar = if (comment is com.example.data.database.VideoCommentEntity) comment.authorAvatar else (comment as com.example.data.database.ReelCommentEntity).authorAvatar
                            val author = if (comment is com.example.data.database.VideoCommentEntity) comment.authorName else (comment as com.example.data.database.ReelCommentEntity).authorName
                            val text = if (comment is com.example.data.database.VideoCommentEntity) comment.text else (comment as com.example.data.database.ReelCommentEntity).text
                            ProfileAvatar(avatarId = avatar, size = 32)
                            Spacer(modifier = Modifier.width(8.dp))
                            Column(
                                modifier = Modifier
                                    .background(Color(0xFFF0F2F5), RoundedCornerShape(12.dp))
                                    .padding(horizontal = 12.dp, vertical = 8.dp)
                            ) {
                                Text(author, fontWeight = FontWeight.Bold, fontSize = 12.sp, color = Color.Black)
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(text, fontSize = 13.sp, color = Color.DarkGray)
                            }
                        }
                    }
                }
            }
            Spacer(modifier = Modifier.height(12.dp))
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .imePadding(),
                verticalAlignment = Alignment.CenterVertically
            ) {
                TextField(
                    value = commentText,
                    onValueChange = { commentText = it },
                    placeholder = { Text("Write a comment...", fontSize = 13.sp) },
                    modifier = Modifier.weight(1f),
                    colors = TextFieldDefaults.colors(
                        focusedIndicatorColor = Color.Transparent,
                        unfocusedIndicatorColor = Color.Transparent,
                        focusedContainerColor = Color(0xFFF0F2F5),
                        unfocusedContainerColor = Color(0xFFF0F2F5)
                    ),
                    shape = RoundedCornerShape(24.dp),
                    singleLine = true
                )
                Spacer(modifier = Modifier.width(8.dp))
                IconButton(
                    onClick = {
                        if (commentText.isNotBlank()) {
                            if (videoId != null) {
                                viewModel.addVideoComment(videoId, commentText)
                            } else if (reelId != null) {
                                viewModel.addReelComment(reelId, commentText)
                            }
                            commentText = ""
                        }
                    },
                    enabled = commentText.isNotBlank()
                ) {
                    Icon(
                        imageVector = Icons.Default.Send,
                        contentDescription = "Send",
                        tint = if (commentText.isNotBlank()) LavenderPrimary else Color.Gray
                    )
                }
            }
        }
    }
}


